ine_number":6754,"utf16_col":34}},"extent_utf16":{"start":{"line_number":6754,"utf16_col":0},"end":{"line_number":6776,"utf16_col":3}}},{"name":"findShadows","kind":"function","ident_start":236625,"ident_end":236636,"extent_start":236610,"extent_end":238002,"fully_qualified_name":"findShadows","ident_utf16":{"start":{"line_number":6782,"utf16_col":15},"end":{"line_number":6782,"utf16_col":26}},"extent_utf16":{"start":{"line_number":6782,"utf16_col":0},"end":{"line_number":6825,"utf16_col":3}}}]}},"codeViewLayoutRoute":{"repo":{"id":277293455,"defaultBranch":"master","name":"DumbLuaParser","ownerLogin":"ReFreezed","currentUserCanPush":false,"isFork":false,"isEmpty":false,"createdAt":"2020-07-05T12:00:37.000Z","ownerAvatar":"https://avatars.githubusercontent.com/u/9154297?v=4","public":true,"private":false,"isOrgOwned":false},"currentUser":null,"uploadToken":"hu-5jwT2qWA969bybKY4PAAyd_RYdanmFwQrLDShO7paxB_OnfL91M6VfQK95fKD2lPABABOcorsVvlIn8vnPw","allShortcutsEnabled":false,"treeExpanded":true,"path":"dumbParser.lua","symbolsExpanded":false,"refInfo":{"name":"master","listCacheKey":"v0:1656008137.54787","canEdit":false,"currentOid":"a14fbbefb47e28c7e29a4721be236e25f4c686f4"},"helpUrl":"https://docs.github.com","findFileWorkerPath":"/assets-cdn/worker/find-file-worker-4e5d7136862a2a48.js","findInFileWorkerPath":"/assets-cdn/worker/find-in-file-worker-4c35b25d88167fef.js","githubDevUrl":null},"codeViewFileTreeLayoutRoute":{"fileTree":{"":{"items":[{"name":".extras","path":".extras","contentType":"directory"},{"name":".gitignore","path":".gitignore","contentType":"file"},{"name":"CHANGELOG.txt","path":"CHANGELOG.txt","contentType":"file"},{"name":"LICENSE.txt","path":"LICENSE.txt","contentType":"file"},{"name":"README.md","path":"README.md","contentType":"file"},{"name":"dumbParser.lua","path":"dumbParser.lua","contentType":"file"},{"name":"examples.lua","path":"examples.lua","contentType":"file"},{"name":"test.lua","path":"test.lua","contentType":"file"},{"name":"testsuite.lua","path":"testsuite.lua","contentType":"file"}],"totalCount":9}},"fileTreeProcessingTime":7.404037,"foldersToFetch":[]},"codeViewBlobLayoutRoute":{"codeLineWrapEnabled":false,"refInfo":{"name":"master","listCacheKey":"v0:1656008137.54787","canEdit":false,"refType":"branch","currentOid":"a14fbbefb47e28c7e29a4721be236e25f4c686f4","canEditOnDefaultBranch":false,"fileExistsOnDefault":true},"path":"dumbParser.lua","blob":{"copilotSWEAgentEnabled":false,"dependabotInfo":{"showConfigurationBanner":false,"configFilePath":null,"networkDependabotPath":"/ReFreezed/DumbLuaParser/network/updates","dismissConfigurationNoticePath":"/settings/dismiss-notice/dependabot_configuration_notice","configurationNoticeDismissed":null},"displayName":"dumbParser.lua","displayUrl":"https://github.com/ReFreezed/DumbLuaParser/blob/master/dumbParser.lua?raw=true","headerInfo":{"blobSize":"235 KB","deleteTooltip":"You must be signed in to make or propose changes","editTooltip":"You must be signed in to make or propose changes","ghDesktopPath":"https://desktop.github.com","isGitLfs":false,"onBranch":true,"shortPath":"5714f71","siteNavLoginPath":"/login?return_to=https%3A%2F%2Fgithub.com%2FReFreezed%2FDumbLuaParser%2Fblob%2Fmaster%2FdumbParser.lua","isCSV":false,"isRichtext":false,"lineInfo":{"truncatedLoc":"6938","truncatedSloc":"5505"},"mode":"file"},"image":false,"isCodeownersFile":null,"isPlain":false,"isValidLegacyIssueTemplate":false,"isIssueTemplate":false,"isDiscussionTemplate":false,"language":"Lua","languageID":213,"large":false,"planSupportInfo":{"repoIsFork":null,"repoOwnedByCurrentUser":null,"requestFullPath":"/ReFreezed/DumbLuaParser/blob/master/dumbParser.lua","showFreeOrgGatedFeatureMessage":null,"showPlanSupportBanner":null,"upgradeDataAttributes":null,"upgradePath":null},"publishBannersInfo":{"dismissActionNoticePath":"/settings/dismiss-notice/publish_action_from_dockerfile","releasePath":"/ReFreezed/DumbLuaParser/releases/new?marketplace=true","showPublishActionBanner":false},"rawBlobUrl":"https://github.com/ReFreezed/DumbLuaParser/raw/refs/heads/master/dumbParser.lua","renderImageOrRaw":false,"shortPath":null,"symbolsEnabled":true,"tabSize":4,"topBannersInfo":{"overridingGlobalFundingFile":false,"globalPreferredFundingPath":null,"showInvalidCitationWarning":false,"citationHelpUrl":"https://docs.github.com/github/creating-cloning-and-archiving-repositories/creating-a-repository-on-github/about-citation-files","actionsOnboardingTip":null},"truncated":false,"viewable":true,"workflowRedirectUrl":null},"copilotInfo":null,"copilotAccessAllowed":false,"copilotSpacesEnabled":false,"modelsAccessAllowed":false,"modelsRepoIntegrationEnabled":false,"isMarketplaceEnabled":true},"codeViewBlobLayoutRoute.StyledBlob":{"rawLines":["--[=[===========================================================","--=","--=  Dumb Lua Parser - Lua parsing library","--=  by Marcus 'ReFreezed' Thunström","--=","--=  Tokenize Lua code or create ASTs (Abstract Syntax Trees)","--=  and convert the data back to Lua.","--=","--=  Version: 2.3 (2022-06-23)","--=","--=  License: MIT (see the bottom of this file)","--=  Website: http://refreezed.com/luaparser/","--=  Documentation: http://refreezed.com/luaparser/docs/","--=","--=  Supported Lua versions: 5.1, 5.2, 5.3, 5.4, LuaJIT","--=","--==============================================================","","1 - Usage","2 - API","  2.1 - Functions","  2.2 - Constants","  2.3 - Settings","3 - Tokens","4 - AST","5 - Other Objects","  5.1 - Stats","  5.2 - Locations","6 - Notes","","","1 - Usage","================================================================","","local parser = require(\"dumbParser\")","","local tokens = parser.tokenizeFile(\"cool.lua\")","local ast    = parser.parse(tokens)","","parser.simplify(ast)","parser.printTree(ast)","","local lua = parser.toLua(ast, true)","print(lua)","","","2 - API","================================================================","","","2.1 - Functions","----------------------------------------------------------------","","tokenize, tokenizeFile","newToken, updateToken, cloneToken, concatTokens","parse, parseExpression, parseFile","newNode, newNodeFast, valueToAst, cloneNode, cloneTree, getChild, setChild, addChild, removeChild","validateTree","traverseTree, traverseTreeReverse","updateReferences","simplify, optimize, minify","toLua","printTokens, printNode, printTree","formatMessage","findDeclaredNames, findGlobalReferences, findShadows","","tokenize()","\ttokens = parser.tokenize( luaString [, pathForErrorMessages=\"?\" ] )","\ttokens = parser.tokenize( luaString [, keepWhitespaceTokens=false, pathForErrorMessages=\"?\" ] )","\tConvert a Lua string into an array of tokens. (See below for more info.)","\tReturns nil and a message on error.","","tokenizeFile()","\ttokens = parser.tokenizeFile( path [, keepWhitespaceTokens=false ] )","\tConvert the contents of a file into an array of tokens. (See below for more info.) Uses io.open().","\tReturns nil and a message on error.","","newToken()","\ttoken = parser.newToken( tokenType, tokenValue )","\tCreate a new token. (See below or search for 'TokenCreation' for more info.)","","updateToken()","\tparser.updateToken( token, tokenValue )","\tUpdate the value and representation of an existing token. (Search for 'TokenModification' for more info.)","","cloneToken()","\ttokenClone = parser.cloneToken( token )","\tClone an existing token.","","concatTokens()","\tluaString = parser.concatTokens( tokens )","\tConcatenate tokens. Whitespace is added between tokens when necessary.","","parse()","\tastNode = parser.parse( tokens )","\tastNode = parser.parse( luaString [, pathForErrorMessages=\"?\" ] )","\tConvert tokens or Lua code into an AST representing a block of code. (See below for more info.)","\tReturns nil and a message on error.","","parseExpression()","\tastNode = parser.parseExpression( tokens )","\tastNode = parser.parseExpression( luaString [, pathForErrorMessages=\"?\" ] )","\tConvert tokens or Lua code into an AST representing a value expression. (See below for more info.)","\tReturns nil and a message on error.","","parseFile()","\tastNode = parser.parseFile( path )","\tConvert a Lua file into an AST. (See below for more info.) Uses io.open().","\tReturns nil and a message on error.","","newNode()","\tastNode = parser.newNode( nodeType, arguments... )","\tCreate a new AST node. (Search for 'NodeCreation' for more info.)","","newNodeFast()","\tastNode = parser.newNodeFast( nodeType, arguments... )","\tSame as newNode() but without any validation. (Search for 'NodeCreation' for more info.)","","valueToAst()","\tastNode = parser.valueToAst( value [, sortTableKeys=false ] )","\tConvert a Lua value (number, string, boolean, nil or table) to an AST.","","cloneNode()","\tastNode = parser.cloneNode( astNode )","\tClone an existing AST node (but not any children).","","cloneTree()","\tastNode = parser.cloneTree( astNode )","\tClone an existing AST node and its children.","","getChild()","\tchildNode = parser.getChild( astNode, fieldName )","\tchildNode = parser.getChild( astNode, fieldName, index )                -- If the node field is an array.","\tchildNode = parser.getChild( astNode, fieldName, index, tableFieldKey ) -- If the node field is a table field array.","\ttableFieldKey = \"key\"|\"value\"","\tGet a child node. (Search for 'NodeFields' for field names.)","","\tThe result is the same as doing the following, but with more error checking:","\tchildNode = astNode[fieldName]","\tchildNode = astNode[fieldName][index]","\tchildNode = astNode[fieldName][index][tableFieldKey]","","setChild()","\tparser.setChild( astNode, fieldName, childNode )","\tparser.setChild( astNode, fieldName, index, childNode )                -- If the node field is an array.","\tparser.setChild( astNode, fieldName, index, tableFieldKey, childNode ) -- If the node field is a table field array.","\ttableFieldKey = \"key\"|\"value\"","\tSet a child node. (Search for 'NodeFields' for field names.)","","\tThe result is the same as doing the following, but with more error checking:","\tastNode[fieldName]                       = childNode","\tastNode[fieldName][index]                = childNode","\tastNode[fieldName][index][tableFieldKey] = childNode","","addChild()","\tparser.addChild( astNode, fieldName, [ index=atEnd, ] childNode )","\tparser.addChild( astNode, fieldName, [ index=atEnd, ] keyNode, valueNode ) -- If the node field is a table field array.","\tAdd a child node to an array field. (Search for 'NodeFields' for field names.)","","\tThe result is the same as doing the following, but with more error checking:","\ttable.insert(astNode[fieldName], index, childNode)","\ttable.insert(astNode[fieldName], index, {key=keyNode, value=valueNode, generatedKey=false})","","removeChild()","\tparser.removeChild( astNode, fieldName [, index=last ] )","\tRemove a child node from an array field. (Search for 'NodeFields' for field names.)","","\tThe result is the same as doing the following, but with more error checking:","\ttable.remove(astNode[fieldName], index)","","isExpression()","\tbool = parser.isExpression( astNode )","\tReturns true for expression nodes and false for statements.","\tNote that call nodes count as expressions for this function, i.e. return true.","","isStatement()","\tbool = parser.isStatement( astNode )","\tReturns true for statements and false for expression nodes.","\tNote that call nodes count as statements for this function, i.e. return true.","","validateTree()","\tisValid, errorMessages = parser.validateTree( astNode )","\tCheck for errors in an AST (e.g. missing condition expressions for if statements).","\terrorMessages is a multi-line string if isValid is false.","","traverseTree()","\tdidStop = parser.traverseTree( astNode, [ leavesFirst=false, ] callback [, topNodeParent=nil, topNodeContainer=nil, topNodeKey=nil ] )","\taction  = callback( astNode, parent, container, key )","\taction  = \"stop\"|\"ignorechildren\"|nil  -- Returning nil (or nothing) means continue traversal.","\tCall a function on all nodes in an AST, going from astNode out to the leaf nodes (or from leaf nodes and inwards if leavesFirst is set).","\tcontainer[key] is the position of the current node in the tree and can be used to replace the node.","","traverseTreeReverse()","\tdidStop = parser.traverseTreeReverse( astNode, [ leavesFirst=false, ] callback [, topNodeParent=nil, topNodeContainer=nil, topNodeKey=nil ] )","\taction  = callback( astNode, parent, container, key )","\taction  = \"stop\"|\"ignorechildren\"|nil  -- Returning nil (or nothing) means continue traversal.","\tCall a function on all nodes in reverse order in an AST, going from astNode out to the leaf nodes (or from leaf nodes and inwards if leavesFirst is set).","\tcontainer[key] is the position of the current node in the tree and can be used to replace the node.","","updateReferences()","\tparser.updateReferences( astNode [, updateTopNodePositionInfo=true ] )","\tUpdate references between nodes in the tree.","\tThis function sets 'parent'+'container'+'key' for all nodes, 'declaration' for identifiers and vararg nodes, and 'label' for goto nodes.","\tIf 'updateTopNodePositionInfo' is false then 'parent', 'container' and 'key' will remain as-is for 'astNode' specifically.","","simplify()","\tstats = parser.simplify( astNode )","\tSimplify/fold expressions and statements involving constants ('1+2' becomes '3', 'false and func()' becomes 'false' etc.).","\tSee the INT_SIZE constant for notes.","\tSee below for more info about stats.","","optimize()","\tstats = parser.optimize( astNode )","\tAttempt to remove nodes that aren't useful, like unused variables, or variables that are essentially constants.","\tCalls simplify() internally.","\tThis function can be quite slow!","\tSee below for more info about stats.","\tNote: References may be out-of-date after calling this.","","minify()","\tstats = parser.minify( astNode [, optimize=false ] )","\tReplace local variable names with short names.","\tThis function can be used to obfuscate the code to some extent.","\tIf 'optimize' is set then optimize() is also called automatically.","\tSee below for more info about stats.","\tNote: References may be out-of-date after calling this.","","toLua()","\tluaString    = parser.toLua( astNode [, prettyOuput=false, nodeCallback ] )","\tnodeCallback = function( node, outputBuffer )","\tConvert an AST to Lua, optionally call a function on each node before they are turned into Lua.","\tAny node in the tree with a .pretty attribute will override the 'prettyOuput' flag for itself and its children.","\tNodes can also have a .prefix and/or .suffix attribute with Lua code to output before/after the node (e.g. declaration.names[1].suffix=\"--[[foo]]\").","\toutputBuffer is an array of Lua code that has been output so far.","\tReturns nil and a message on error.","","printTokens()","\tparser.printTokens( tokens )","\tPrint tokens to stdout.","","printNode()","\tparser.printNode( astNode )","\tPrint information about an AST node to stdout.","","printTree()","\tparser.printTree( astNode )","\tPrint the structure of a whole AST to stdout.","","formatMessage()","\tmessage = parser.formatMessage( [ prefix=\"Info\", ] token,    formatString, ... )","\tmessage = parser.formatMessage( [ prefix=\"Info\", ] astNode,  formatString, ... )","\tmessage = parser.formatMessage( [ prefix=\"Info\", ] location, formatString, ... )","\tFormat a message to contain a code preview window with an arrow pointing at the target token, node or location.","\tThis is used internally for formatting error messages.","","\t-- Example:","\tif identifier.name ~= \"good\" then","\t\tprint(parser.formatMessage(\"Error\", identifier, \"This identifier is not good!\"))","\t\tprint(parser.formatMessage(currentStatement, \"Current statement.\"))","\tend","","findDeclaredNames()","\tidentifiers = parser.findDeclaredNames( astNode )","\tFind all declared names in the tree (i.e. identifiers from AstDeclaration, AstFunction and AstFor nodes).","","findGlobalReferences()","\tidentifiers = parser.findGlobalReferences( astNode )","\tFind all identifiers not referring to local variables in the tree.","\tNote: updateReferences() must be called at some point before you call this - otherwise all variables will be seen as globals!","","findShadows()","\tshadowSequences = parser.findShadows( astNode )","\tshadowSequences = { shadowSequence1, ... }","\tshadowSequence  = { shadowingIdentifier, shadowedIdentifier1, ... }","\tFind local variable shadowing in the tree. Each shadowSequence is an array of declared identifiers where each identifier shadows the next one.","\tNote: updateReferences() must be called at some point before you call this - otherwise all variables will be seen as globals!","\tNote: Shadowing of globals cannot be detected by the function as that would require knowledge of all potential globals in your program. (See findGlobalReferences())","","","2.2 - Constants","----------------------------------------------------------------","","INT_SIZE, MAX_INT, MIN_INT","VERSION","","INT_SIZE","\tparser.INT_SIZE = integer","\tHow many bits integers have. In Lua 5.3 and later this is usually 64, and in earlier versions it's 32.","\tThe int size may affect how bitwise operations involving only constants get simplified (see simplify()),","\te.g. the expression '-1\u003e\u003e1' becomes 2147483647 in Lua 5.2 but 9223372036854775807 in Lua 5.3.","","MAX_INT","\tparser.MAX_INT = integer","\tThe highest representable positive signed integer value, according to INT_SIZE.","\tThis is the same value as math.maxinteger in Lua 5.3 and later.","\tThis only affects simplification of some bitwise operations.","","MIN_INT","\tparser.MIN_INT = integer","\tThe highest representable negative signed integer value, according to INT_SIZE.","\tThis is the same value as math.mininteger in Lua 5.3 and later.","\tThis only affects simplification of some bitwise operations.","","VERSION","\tparser.VERSION","\tThe parser's version number (e.g. \"1.0.2\").","","","2.3 - Settings","----------------------------------------------------------------","","printIds, printLocations","indentation","constantNameReplacementStringMaxLength","","printIds","\tparser.printIds = bool","\tIf AST node IDs should be printed. (All nodes gets assigned a unique ID when created.)","\tDefault: false.","","printLocations","\tparser.printLocations = bool","\tIf the file location (filename and line number) should be printed for each token or AST node.","\tDefault: false.","","indentation","\tparser.indentation = string","\tThe indentation used when printing ASTs (with printTree()).","\tDefault: 4 spaces.","","constantNameReplacementStringMaxLength","\tparser.constantNameReplacementStringMaxLength = length","\tNormally optimize() replaces variable names that are effectively constants with their value.","\tThe exception is if the value is a string that's longer than what this setting specifies.","\tDefault: 200.","","\t-- Example:","\tlocal ast = parser.parse[==[","\t\tlocal short = \"a\"","\t\tlocal long  = \"xy\"","\t\tfunc(short, long)","\t]==]","\tparser.constantNameReplacementStringMaxLength = 1","\tparser.optimize(ast)","\tprint(parser.toLua(ast)) -- local long=\"xy\";func(\"a\",long);","","","3 - Tokens","================================================================","","Tokens are represented by tables.","","Token fields:","","\ttype           -- Token type. (See below.)","\tvalue          -- Token value. All token types have a string value, except \"number\" tokens which have a number value.","\trepresentation -- The token's code representation. (Strings have surrounding quotes, comments start with \"--\" etc.)","","\tsourceString   -- The original source string, or \"\" if there is none.","\tsourcePath     -- Path to the source file, or \"?\" if there is none.","","\tlineStart      -- Start line number in sourceString, or 0 by default.","\tlineEnd        -- End line number in sourceString, or 0 by default.","\tpositionStart  -- Start byte position in sourceString, or 0 by default.","\tpositionEnd    -- End byte position in sourceString, or 0 by default.","","Token types:","","\t\"comment\"     -- A comment.","\t\"identifier\"  -- Word that is not a keyword.","\t\"keyword\"     -- Lua keyword.","\t\"number\"      -- Number literal.","\t\"punctuation\" -- Any punctuation, e.g. \"..\" or \"(\".","\t\"string\"      -- String value.","\t\"whitespace\"  -- Sequence of whitespace characters.","","","4 - AST","================================================================","","AST nodes are represented by tables.","","Node types:","","\t\"assignment\"  -- Assignment of one or more values to one or more variables.","\t\"binary\"      -- Binary expression (operation with two operands, e.g. \"+\" or \"and\").","\t\"block\"       -- List of statements. Blocks inside blocks are 'do...end' statements.","\t\"break\"       -- Loop break statement.","\t\"call\"        -- Function call.","\t\"declaration\" -- Declaration of one or more local variables, possibly with initial values.","\t\"for\"         -- A 'for' loop.","\t\"function\"    -- Anonymous function header and body.","\t\"goto\"        -- A jump to a label.","\t\"identifier\"  -- An identifier.","\t\"if\"          -- If statement with a condition, a body if the condition is true, and possibly another body if the condition is false.","\t\"label\"       -- Label for goto commands.","\t\"literal\"     -- Number, string, boolean or nil literal.","\t\"lookup\"      -- Field lookup on an object.","\t\"repeat\"      -- A 'repeat' loop.","\t\"return\"      -- Function/chunk return statement, possibly with values.","\t\"table\"       -- Table constructor.","\t\"unary\"       -- Unary expression (operation with one operand, e.g. \"-\" or \"not\").","\t\"vararg\"      -- Vararg expression (\"...\").","\t\"while\"       -- A 'while' loop.","","Node fields: (Search for 'NodeFields'.)","","","5 - Other Objects","================================================================","","","5.1 - Stats","----------------------------------------------------------------","","Some functions return a stats table which contains these fields:","","\tnodeReplacements   -- Array of locations. Locations of nodes that were replaced. (See below for location info.)","\tnodeRemovals       -- Array of locations. Locations of nodes or tree branches that were removed. (See below for location info.)","\tnodeRemoveCount    -- Number. How many nodes were removed, including subnodes of nodeRemovals.","","\trenameCount        -- Number. How many identifiers were renamed.","\tgeneratedNameCount -- Number. How many unique names were generated.","","","5.2 - Locations","----------------------------------------------------------------","","Locations are tables with these fields:","","\tsourceString -- The original source string, or \"\" if there is none.","\tsourcePath   -- Path to the source file, or \"?\" if there is none.","","\tline         -- Line number in sourceString, or 0 by default.","\tposition     -- Byte position in sourceString, or 0 by default.","","\tnode         -- The node the location points to, or nil if there is none.","\treplacement  -- The node that replaced 'node', or nil if there is none. (This is set for stats.nodeReplacements.)","","","6 - Notes","================================================================","","Special number notation rules.","","\tThe expression '-n' is parsed as a single number literal if 'n' is a","\tnumeral (i.e. the result is a negative number).","","\tThe expression 'n/0' is parsed as a single number literal if 'n' is a","\tnumeral. If 'n' is positive then the result is math.huge, if 'n' is","\tnegative then the result is -math.huge, or if 'n' is 0 then the result is","\tNaN.","","","-============================================================]=]","","local PARSER_VERSION = \"2.3.0\"","","local NORMALIZE_MINUS_ZERO, HANDLE_ENV -- Should HANDLE_ENV be a setting?","do","\tlocal n              = 0","\tNORMALIZE_MINUS_ZERO = tostring(-n) == \"0\" -- Lua 5.3+ normalizes -0 to 0.","end","do","\tlocal pcall = pcall","\tlocal _ENV  = nil","\tHANDLE_ENV  = not pcall(function() return _G end) -- Looking up the global _G will raise an error if _ENV is supported (Lua 5.2+).","end","","local assert       = assert","local error        = error","local ipairs       = ipairs","local loadstring   = loadstring or load","local pairs        = pairs","local print        = print","local select       = select","local tonumber     = tonumber","local tostring     = tostring","local type         = type","","local ioOpen       = io.open","local ioWrite      = io.write","","local jit          = jit","","local mathFloor    = math.floor","local mathMax      = math.max","local mathMin      = math.min","local mathType     = math.type -- May be nil.","","local F            = string.format","local stringByte   = string.byte","local stringChar   = string.char","local stringFind   = string.find","local stringGmatch = string.gmatch","local stringGsub   = string.gsub","local stringMatch  = string.match","local stringRep    = string.rep","local stringSub    = string.sub","","local tableConcat  = table.concat","local tableInsert  = table.insert","local tableRemove  = table.remove","local tableSort    = table.sort","local tableUnpack  = table.unpack or unpack","","local maybeWrapInt = (","\t(jit and function(n)","\t\t-- 'n' might be cdata (i.e. a 64-bit integer) here. We have to limit the range","\t\t-- with mod once before we convert it to a Lua number to not lose precision,","\t\t-- but the result might be negative (and still out of range somehow!) so we","\t\t-- have to use mod again. Gah!","\t\treturn tonumber(n % 0x100000000) % 0x100000000 -- 0x100000000 == 2^32","\tend)","\tor (_VERSION == \"Lua 5.2\" and require\"bit32\".band)","\tor function(n)  return n  end",")","","local parser","","","","local function newSet(values)","\tlocal set = {}","\tfor _, v in ipairs(values) do","\t\tset[v] = true","\tend","\treturn set","end","local function newCharSet(chars)","\treturn newSet{ stringByte(chars, 1, #chars) }","end","","local KEYWORDS = newSet{","\t\"and\", \"break\", \"do\", \"else\", \"elseif\", \"end\", \"false\", \"for\", \"function\", \"goto\", \"if\",","\t\"in\", \"local\", \"nil\", \"not\", \"or\", \"repeat\", \"return\", \"then\", \"true\", \"until\", \"while\",","}","local PUNCTUATION = newSet{","\t\"+\",  \"-\",  \"*\",  \"/\",  \"%\",  \"^\",  \"#\",","\t\"\u0026\",  \"~\",  \"|\",  \"\u003c\u003c\", \"\u003e\u003e\", \"//\",","\t\"==\", \"~=\", \"\u003c=\", \"\u003e=\", \"\u003c\",  \"\u003e\",  \"=\",","\t\"(\",  \")\",  \"{\",  \"}\",  \"[\",  \"]\",  \"::\",","\t\";\",  \":\",  \",\",  \".\",  \"..\", \"...\",","}","local OPERATORS_UNARY = newSet{","\t\"-\", \"not\", \"#\", \"~\",","}","local OPERATORS_BINARY = newSet{","\t\"+\",   \"-\",  \"*\", \"/\",  \"//\", \"^\", \"%\",","\t\"\u0026\",   \"~\",  \"|\", \"\u003e\u003e\", \"\u003c\u003c\", \"..\",","\t\"\u003c\",   \"\u003c=\", \"\u003e\", \"\u003e=\", \"==\", \"~=\",","\t\"and\", \"or\",","}","local OPERATOR_PRECEDENCE = {","\t[\"or\"]  = 1,","\t[\"and\"] = 2,","\t[\"\u003c\"]   = 3,  [\"\u003e\"] = 3, [\"\u003c=\"] = 3, [\"\u003e=\"] = 3, [\"~=\"] = 3, [\"==\"] = 3,","\t[\"|\"]   = 4,","\t[\"~\"]   = 5,","\t[\"\u0026\"]   = 6,","\t[\"\u003c\u003c\"]  = 7,  [\"\u003e\u003e\"]  = 7,","\t[\"..\"]  = 8,","\t[\"+\"]   = 9,  [\"-\"] = 9,","\t[\"*\"]   = 10, [\"/\"] = 10, [\"//\"] = 10, [\"%\"] = 10,","\tunary   = 11, -- \"-\", \"not\", \"#\", \"~\"","\t[\"^\"]   = 12,","}","","local EXPRESSION_NODES = newSet{ \"binary\", \"call\", \"function\", \"identifier\", \"literal\", \"lookup\", \"table\", \"unary\", \"vararg\" }","local STATEMENT_NODES  = newSet{ \"assignment\", \"block\", \"break\", \"call\", \"declaration\", \"for\", \"goto\", \"if\", \"label\", \"repeat\", \"return\", \"while\" }","","local TOKEN_BYTES = {","\tNAME_START      = newCharSet\"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz_\",","\tDASH            = newCharSet\"-\",","\tNUM             = newCharSet\"0123456789\",","\tQUOTE           = newCharSet\"\\\"'\",","\tSQUARE          = newCharSet\"[\",","\tDOT             = newCharSet\".\",","\tPUNCT_TWO_CHARS = newCharSet\".=~\u003c\u003e:/\u003c\u003e\",","\tPUNCT_ONE_CHAR  = newCharSet\"+-*/%^#\u003c\u003e=(){}[];:,.\u0026~|\",","}","","local NUMERAL_PATTERNS = {","\tHEX_FRAC_EXP = stringGsub(\"^( 0[Xx] (%x*) %.(%x+) [Pp]([-+]?%x+) )\", \" +\", \"\"),","\tHEX_FRAC     = stringGsub(\"^( 0[Xx] (%x*) %.(%x+)                )\", \" +\", \"\"),","\tHEX_EXP      = stringGsub(\"^( 0[Xx] (%x+) %.?     [Pp]([-+]?%x+) )\", \" +\", \"\"),","\tHEX          = stringGsub(\"^( 0[Xx]  %x+  %.?                    )\", \" +\", \"\"),","\tBIN          = stringGsub(\"^( 0[Bb]  [01]+                       )\", \" +\", \"\"),","\tDEC_FRAC_EXP = stringGsub(\"^(        %d*  %.%d+   [Ee][-+]?%d+   )\", \" +\", \"\"),","\tDEC_FRAC     = stringGsub(\"^(        %d*  %.%d+                  )\", \" +\", \"\"),","\tDEC_EXP      = stringGsub(\"^(        %d+  %.?     [Ee][-+]?%d+   )\", \" +\", \"\"),","\tDEC          = stringGsub(\"^(        %d+  %.?                    )\", \" +\", \"\"),","}","","local INT_SIZE, MAX_INT, MIN_INT","do","\tlocal hex = F(\"%x\", maybeWrapInt(-1))","\tINT_SIZE  = #hex * 4 -- This should generally be 64 for Lua 5.3+ and 32 for earlier.","\tMAX_INT   = math.maxinteger or tonumber(stringGsub(hex, \"f\", \"7\", 1), 16)","\tMIN_INT   = math.mininteger or -MAX_INT-1","end","","local nextSerialNumber = 1","","","","-- :NodeFields","","local function populateCommonNodeFields(token, node)","\t-- All nodes have these fields.","\tnode.id          = nextSerialNumber","\tnextSerialNumber = nextSerialNumber + 1","","\tnode.sourceString = token and token.sourceString or \"\"","\tnode.sourcePath   = token and token.sourcePath   or \"?\"","","\tnode.token    = token","\tnode.line     = token and token.lineStart     or 0","\tnode.position = token and token.positionStart or 0","","\t-- These fields are set by updateReferences():","\t-- node.parent    = nil -- Refers to the node's parent in the tree.","\t-- node.container = nil -- Refers to the specific table that the node is in, which could be the parent itself or a field in the parent.","\t-- node.key       = nil -- Refers to the specific field in the container that the node is in (which is either a string or an integer).","","\t-- toLua() uses these fields if present:","\t-- node.pretty = bool","\t-- node.prefix = luaString","\t-- node.suffix = luaString","","\treturn node","end","","-- AST expressions.","local function AstIdentifier (token,name)return populateCommonNodeFields(token,{","\ttype        = \"identifier\",","\tname        = name,  -- String.","\tattribute   = \"\",    -- \"\" | \"close\" | \"const\"  -- Only used in declarations.","\tdeclaration = nil,   -- AstIdentifier (whose parent is an AstDeclaration, AstFunction or AstFor). Updated by updateReferences(). This is nil for globals.","})end","local function AstVararg (token)return populateCommonNodeFields(token,{","\ttype        = \"vararg\",","\tdeclaration = nil,   -- AstVararg (whose parent is an AstFunction). Updated by updateReferences(). This is nil in the main chunk (or in a non-vararg function, which is probably an error).","\tadjustToOne = false, -- True if parentheses surround the vararg.","})end","local function AstLiteral (token,v)return populateCommonNodeFields(token,{","\ttype        = \"literal\",","\tvalue       = v,     -- Number, string, boolean or nil.","})end","local function AstTable (token)return populateCommonNodeFields(token,{","\ttype        = \"table\",","\tfields      = {},    -- Array of {key=expression, value=expression, generatedKey=bool}. generatedKey is true for implicit keys (i.e. {x,y}) and false for explicit keys (i.e. {a=x,b=y}). Note that the state of generatedKey affects the output of toLua()! 'key' may be nil if generatedKey is true.","})end","local function AstLookup (token)return populateCommonNodeFields(token,{","\ttype        = \"lookup\",","\tobject      = nil,   -- Expression.","\tmember      = nil,   -- Expression.","})end","local function AstUnary (token,op)return populateCommonNodeFields(token,{","\ttype        = \"unary\",","\toperator    = op,    -- \"-\" | \"not\" | \"#\" | \"~\"","\texpression  = nil,   -- Expression.","})end","local function AstBinary (token,op)return populateCommonNodeFields(token,{","\ttype        = \"binary\",","\toperator    = op,    -- \"+\" | \"-\" | \"*\" | \"/\" | \"//\" | \"^\" | \"%\" | \"\u0026\" | \"~\" | \"|\" | \"\u003e\u003e\" | \"\u003c\u003c\" | \"..\" | \"\u003c\" | \"\u003c=\" | \"\u003e\" | \"\u003e=\" | \"==\" | \"~=\" | \"and\" | \"or\"","\tleft        = nil,   -- Expression.","\tright       = nil,   -- Expression.","})end","local function AstCall (token)return populateCommonNodeFields(token,{ -- Calls can be both expressions and statements.","\ttype        = \"call\",","\tcallee      = nil,   -- Expression.","\targuments   = {},    -- Array of expressions.","\tmethod      = false, -- True if the call is a method call. Method calls must have a callee that is a lookup with a member expression that is a string literal that can pass as an identifier.","\tadjustToOne = false, -- True if parentheses surround the call.","})end","local function AstFunction (token)return populateCommonNodeFields(token,{","\ttype        = \"function\",","\tparameters  = {},    -- Array of AstIdentifier and maybe an AstVararg at the end.","\tbody        = nil,   -- AstBlock.","})end","","-- AST statements.","local function AstBreak (token)return populateCommonNodeFields(token,{","\ttype        = \"break\",","})end","local function AstReturn (token)return populateCommonNodeFields(token,{","\ttype        = \"return\",","\tvalues      = {},    -- Array of expressions.","})end","local function AstLabel (token,name)return populateCommonNodeFields(token,{","\ttype        = \"label\",","\tname        = name,  -- String. The value must be able to pass as an identifier.","})end","local function AstGoto (token,name)return populateCommonNodeFields(token,{","\ttype        = \"goto\",","\tname        = name,  -- String. The value must be able to pass as an identifier.","\tlabel       = nil,   -- AstLabel. Updated by updateReferences().","})end","local function AstBlock (token)return populateCommonNodeFields(token,{","\ttype        = \"block\",","\tstatements  = {},    -- Array of statements.","})end","local function AstDeclaration (token)return populateCommonNodeFields(token,{","\ttype        = \"declaration\",","\tnames       = {},    -- Array of AstIdentifier.","\tvalues      = {},    -- Array of expressions.","})end","local function AstAssignment (token)return populateCommonNodeFields(token,{","\ttype        = \"assignment\",","\ttargets     = {},    -- Mixed array of AstIdentifier and AstLookup.","\tvalues      = {},    -- Array of expressions.","})end","local function AstIf (token)return populateCommonNodeFields(token,{","\ttype        = \"if\",","\tcondition   = nil,   -- Expression.","\tbodyTrue    = nil,   -- AstBlock.","\tbodyFalse   = nil,   -- AstBlock or nil.","})end","local function AstWhile (token)return populateCommonNodeFields(token,{","\ttype        = \"while\",","\tcondition   = nil,   -- Expression.","\tbody        = nil,   -- AstBlock.","})end","local function AstRepeat (token)return populateCommonNodeFields(token,{","\ttype        = \"repeat\",","\tbody        = nil,   -- AstBlock.","\tcondition   = nil,   -- Expression.","})end","local function AstFor (token,kind)return populateCommonNodeFields(token,{","\ttype        = \"for\",","\tkind        = kind,  -- \"numeric\" | \"generic\"","\tnames       = {},    -- Array of AstIdentifier.","\tvalues      = {},    -- Array of expressions.","\tbody        = nil,   -- AstBlock.","})end","","","","local CHILD_FIELDS = {","\t[\"identifier\"]  = {},","\t[\"vararg\"]      = {},","\t[\"literal\"]     = {},","\t[\"table\"]       = {fields=\"tablefields\"},","\t[\"lookup\"]      = {object=\"node\", member=\"node\"},","\t[\"unary\"]       = {expressions=\"node\"},","\t[\"binary\"]      = {left=\"node\", right=\"node\"},","\t[\"call\"]        = {callee=\"node\", arguments=\"nodearray\"},","\t[\"function\"]    = {parameters=\"nodearray\", body=\"node\"},","\t[\"break\"]       = {},","\t[\"return\"]      = {values=\"nodearray\"},","\t[\"label\"]       = {},","\t[\"goto\"]        = {},","\t[\"block\"]       = {statements=\"nodearray\"},","\t[\"declaration\"] = {names=\"nodearray\", values=\"nodearray\"},","\t[\"assignment\"]  = {targets=\"nodearray\", values=\"nodearray\"},","\t[\"if\"]          = {condition=\"node\", bodyTrue=\"node\", bodyFalse=\"node\"},","\t[\"while\"]       = {condition=\"node\", body=\"node\"},","\t[\"repeat\"]      = {body=\"node\", condition=\"node\"},","\t[\"for\"]         = {names=\"nodearray\", values=\"nodearray\", body=\"node\"},","}","","","","local function Stats()","\treturn {","\t\t-- simplify() and optimize():","\t\tnodeReplacements   = {--[[ location1, ... ]]},","\t\tnodeRemovals       = {--[[ location1, ... ]]},","\t\tnodeRemoveCount    = 0,","","\t\t-- minify():","\t\trenameCount        = 0,","\t\tgeneratedNameCount = 0,","\t}","end","","-- location = Location( sourceLocation [, extraKey, extraValue ] )","-- location = Location( sourceNode     [, extraKey, extraValue ] )","local function Location(sourceLocOrNode, extraK, extraV)","\tlocal loc = {","\t\tsourceString = sourceLocOrNode.sourceString,","\t\tsourcePath   = sourceLocOrNode.sourcePath,","","\t\tline     = sourceLocOrNode.line,","\t\tposition = sourceLocOrNode.position,","","\t\tnode = sourceLocOrNode.type and sourceLocOrNode or nil,","\t}","\tif extraK then","\t\tloc[extraK] = extraV","\tend","\treturn loc","end","","","","-- count = countString( haystack, needle [, plain=false ] )","local function countString(haystack, needle, plain)","\tlocal count = 0","\tlocal pos   = 1","","\twhile true do","\t\tlocal _, i2 = stringFind(haystack, needle, pos, plain)","\t\tif not i2 then  return count  end","","\t\tcount = count + 1","\t\tpos   = i2    + 1","\tend","end","","-- count = countSubString( haystack, startPosition, endPosition, needle [, plain=false ] )","local function countSubString(haystack, pos, posEnd, needle, plain)","\tlocal count = 0","","\twhile true do","\t\tlocal _, i2 = stringFind(haystack, needle, pos, plain)","\t\tif not i2 or i2 \u003e posEnd then  return count  end","","\t\tcount = count + 1","\t\tpos   = i2    + 1","\tend","end","","","","-- errorf( [ level=1, ] format, ... )","local function errorf(level, s, ...)","\tif type(level) == \"number\" then","\t\terror(F(s, ...), (level == 0 and 0 or (1+level)))","\telse","\t\terror(F(level, s, ...), 2)","\tend","end","","-- assertArg1( functionName, argumentNumber, value, expectedType                 [, level=2 ] )","-- assertArg2( functionName, argumentNumber, value, expectedType1, expectedType2 [, level=2 ] )","local function assertArg1(funcName, argNum, v, expectedType, level)","\tif type(v) == expectedType then  return  end","\terrorf(1+(level or 2), \"Bad argument #%d to '%s'. (Expected %s, got %s)\", argNum, funcName, expectedType, type(v))","end","local function assertArg2(funcName, argNum, v, expectedType1, expectedType2, level)","\tif type(v) == expectedType1 or type(v) == expectedType2 then  return  end","\terrorf(1+(level or 2), \"Bad argument #%d to '%s'. (Expected %s or %s, got %s)\", argNum, funcName, expectedType1, expectedType2, type(v))","end","","","","local ensurePrintable","do","\tlocal CONTROL_TO_READABLE = {","\t\t[\"\\0\"] = \"{NUL}\",","\t\t[\"\\n\"] = \"{NL}\",","\t\t[\"\\r\"] = \"{CR}\",","\t}","","\t--[[local]] function ensurePrintable(s)","\t\treturn (stringGsub(s, \"[%z\\1-\\31\\127-\\255]\", function(c)","\t\t\treturn CONTROL_TO_READABLE[c] or (stringByte(c) \u003c= 31 or stringByte(c) \u003e= 127) and F(\"{%d}\", stringByte(c)) or nil","\t\tend))","\tend","end","","","","local function removeUnordered(t, i)","\tlocal len = #t","\tif i \u003e len or i \u003c 1 then  return  end","","\t-- Note: This does the correct thing if i==len too.","\tt[i]   = t[len]","\tt[len] = nil","end","","local function removeItemUnordered(t, v)","\tfor i = 1, #t do","\t\tif t[i] == v then","\t\t\tremoveUnordered(t, i)","\t\t\treturn","\t\tend","\tend","end","","","","local function getLineNumber(s, pos)","\treturn 1 + countSubString(s, 1, pos-1, \"\\n\", true)","end","","","","local formatMessageInFile","do","\tlocal function findStartOfLine(s, pos, canBeEmpty)","\t\twhile pos \u003e 1 do","\t\t\tif stringByte(s, pos-1) == 10--[[\\n]] and (canBeEmpty or stringByte(s, pos) ~= 10--[[\\n]]) then  break  end","\t\t\tpos = pos - 1","\t\tend","\t\treturn mathMax(pos, 1)","\tend","\tlocal function findEndOfLine(s, pos)","\t\twhile pos \u003c #s do","\t\t\tif stringByte(s, pos+1) == 10--[[\\n]] then  break  end","\t\t\tpos = pos + 1","\t\tend","\t\treturn mathMin(pos, #s)","\tend","","\tlocal function getSubTextLength(s, pos, posEnd)","\t\tlocal len = 0","","\t\twhile pos \u003c= posEnd do","\t\t\tif stringByte(s, pos) == 9 then -- '\\t'","\t\t\t\tlen = len + 4","\t\t\t\tpos = pos + 1","\t\t\telse","\t\t\t\tlocal _, i2 = stringFind(s, \"^[%z\\1-\\127\\194-\\253][\\128-\\191]*\", pos)","\t\t\t\tif i2 and i2 \u003c= posEnd then","\t\t\t\t\tlen = len + 1","\t\t\t\t\tpos = i2  + 1","\t\t\t\telse","\t\t\t\t\tlen = len + 1","\t\t\t\t\tpos = pos + 1","\t\t\t\tend","\t\t\tend","\t\tend","","\t\treturn len","\tend","","\t--[[local]] function formatMessageInFile(prefix, contents, path, pos, agent, s, ...)","\t\tif agent ~= \"\" then","\t\t\tagent = \"[\"..agent..\"] \"","\t\tend","","\t\ts = F(s, ...)","","\t\tif contents == \"\" then","\t\t\treturn F(\"%s @ %s: %s%s\", prefix, path, agent, s)","\t\tend","","\t\tpos      = mathMin(mathMax(pos, 1), #contents+1)","\t\tlocal ln = getLineNumber(contents, pos)","","\t\tlocal lineStart     = findStartOfLine(contents, pos, true)","\t\tlocal lineEnd       = findEndOfLine  (contents, pos-1)","\t\tlocal linePre1Start = findStartOfLine(contents, lineStart-1, false)","\t\tlocal linePre1End   = findEndOfLine  (contents, linePre1Start-1)","\t\tlocal linePre2Start = findStartOfLine(contents, linePre1Start-1, false)","\t\tlocal linePre2End   = findEndOfLine  (contents, linePre2Start-1)","\t\t-- print(F(\"pos %d | lines %d..%d, %d..%d, %d..%d\", pos, linePre2Start,linePre2End+1, linePre1Start,linePre1End+1, lineStart,lineEnd+1)) -- DEBUG","","\t\treturn F(\"%s @ %s:%d: %s%s\\n\u003e\\n%s%s%s\u003e-%s^\",","\t\t\tprefix, path, ln, agent, s,","\t\t\t(linePre2Start \u003c linePre1Start and linePre2Start \u003c= linePre2End) and F(\"\u003e %s\\n\", (stringGsub(stringSub(contents, linePre2Start, linePre2End), \"\\t\", \"    \"))) or \"\",","\t\t\t(linePre1Start \u003c lineStart     and linePre1Start \u003c= linePre1End) and F(\"\u003e %s\\n\", (stringGsub(stringSub(contents, linePre1Start, linePre1End), \"\\t\", \"    \"))) or \"\",","\t\t\t(                                  lineStart     \u003c= lineEnd    ) and F(\"\u003e %s\\n\", (stringGsub(stringSub(contents, lineStart,     lineEnd    ), \"\\t\", \"    \"))) or \"\u003e\\n\",","\t\t\tstringRep(\"-\", getSubTextLength(contents, lineStart, pos-1))","\t\t)","\tend","end","","local function formatMessageAtToken(prefix, token, agent, s, ...)","\treturn (formatMessageInFile(prefix, (token and token.sourceString or \"\"), (token and token.sourcePath or \"?\"), (token and token.positionStart or 0), agent, s, ...))","end","local function formatMessageAfterToken(prefix, token, agent, s, ...)","\treturn (formatMessageInFile(prefix, (token and token.sourceString or \"\"), (token and token.sourcePath or \"?\"), (token and token.positionEnd+1 or 0), agent, s, ...))","end","","local function formatMessageAtNode(prefix, node, agent, s, ...)","\treturn (formatMessageInFile(prefix, node.sourceString, node.sourcePath, node.position, agent, s, ...))","end","","local function formatMessageHelper(argNumOffset, prefix, nodeOrLocOrToken, s, ...)","\tassertArg1(\"formatMessage\", 1+argNumOffset, prefix,           \"string\", 3)","\tassertArg1(\"formatMessage\", 2+argNumOffset, nodeOrLocOrToken, \"table\",  3)","\tassertArg1(\"formatMessage\", 3+argNumOffset, s,                \"string\", 3)","","\tlocal formatter = nodeOrLocOrToken.representation and formatMessageAtToken or formatMessageAtNode","\treturn (formatter(prefix, nodeOrLocOrToken, \"\", s, ...))","end","","-- message = formatMessage( [ prefix=\"Info\", ] token,    s, ... )","-- message = formatMessage( [ prefix=\"Info\", ] astNode,  s, ... )","-- message = formatMessage( [ prefix=\"Info\", ] location, s, ... )","local function formatMessage(prefix, ...)","\tif type(prefix) == \"string\" then","\t\treturn (formatMessageHelper(0, prefix, ...))","\telse","\t\treturn (formatMessageHelper(-1, \"Info\", prefix, ...))","\tend","","end","","","","local function formatErrorInFile    (...)  return formatMessageInFile    (\"Error\", ...)  end","local function formatErrorAtToken   (...)  return formatMessageAtToken   (\"Error\", ...)  end","local function formatErrorAfterToken(...)  return formatMessageAfterToken(\"Error\", ...)  end","local function formatErrorAtNode    (...)  return formatMessageAtNode    (\"Error\", ...)  end","","","","local function where(node, s, ...)","\tif not node then","\t\tprint(\"[Where] No node here!\")","\telseif s then","\t\tprint(formatMessageAtNode(\"Info\", node, \"Where\", s, ...))","\telse","\t\tprint(formatMessageAtNode(\"Info\", node, \"Where\", \"Here!\"))","\tend","end","","","","local function iprev(t, i)","\ti       = i-1","\tlocal v = t[i]","","\tif v ~= nil then  return i, v  end","end","","local function ipairsr(t)","\treturn iprev, t, #t+1","end","","","","-- index = indexOf( array, value [, startIndex=1, endIndex=#array ] )","local function indexOf(t, v, i1, i2)","\tfor i = (i1 or 1), (i2 or #t) do","\t\tif t[i] == v then  return i  end","\tend","\treturn nil","end","","-- item, index = itemWith1    ( array, key, value )","-- item, index = lastItemWith1( array, key, value )","local function itemWith1(t, k, v)","\tfor i, item in ipairs(t) do","\t\tif item[k] == v then  return item, i  end","\tend","\treturn nil","end","local function lastItemWith1(t, k, v)","\tfor i, item in ipairsr(t) do","\t\tif item[k] == v then  return item, i  end","\tend","\treturn nil","end","","","","-- text = getRelativeLocationText( sourcePathOfInterest, lineNumberOfInterest, otherSourcePath, otherLineNumber )","-- text = getRelativeLocationText( lineNumberOfInterest, otherLineNumber )","local function getRelativeLocationText(sourcePath, ln, otherSourcePath, otherLn)","\tif type(sourcePath) ~= \"string\" then","\t\tsourcePath, ln, otherSourcePath, otherLn = \"\", sourcePath, \"\", ln","\tend","","\tif not (ln \u003e 0) then","\t\treturn \"at \u003cUnknownLocation\u003e\"","\tend","","\tif sourcePath ~= otherSourcePath         then  return F(\"at %s:%d\", sourcePath, ln)  end","\tif ln+1       == otherLn and otherLn \u003e 0 then  return F(\"on the previous line\")  end","\tif ln-1       == otherLn and otherLn \u003e 0 then  return F(\"on the next line\")  end","\tif ln         ~= otherLn                 then  return F(\"on line %d\", ln)  end","\treturn \"on the same line\"","end","","-- text = getRelativeLocationTextForToken( tokens, tokenOfInterest, otherToken )","local function getRelativeLocationTextForToken(tokens, tokOfInterest, otherTok)","\treturn getRelativeLocationText((tokens[tokOfInterest] and tokens[tokOfInterest].lineStart or 0), (tokens[otherTok] and tokens[otherTok].lineStart or 0))","end","","--[[","-- text = getRelativeLocationTextForNode( nodeOfInterest, otherNode )","-- text = getRelativeLocationTextForNode( nodeOfInterest, otherSourcePath, otherLineNumber )","local function getRelativeLocationTextForNode(nodeOfInterest, otherSourcePath, otherLn)","\tif type(otherSourcePath) == \"table\" then","\t\treturn getRelativeLocationTextForNode(nodeOfInterest, otherSourcePath.sourcePath, otherSourcePath.line)","\tend","","\tif not (nodeOfInterest.sourcePath ~= \"?\" and nodeOfInterest.line \u003e 0) then","\t\treturn \"at \u003cUnknownLocation\u003e\"","\tend","","\treturn getRelativeLocationText(nodeOfInterest.sourcePath, nodeOfInterest.line, otherSourcePath, otherLn)","end","]]","","","","local function formatNumber(n)","\t-- @Speed: Cache!","","\t-- 64-bit int in LuaJIT (is what we assume, anyway).","\tif jit and type(n) == \"cdata\" then","\t\tlocal nStr = tostring(n)","","\t\tif stringFind(nStr, \"i$\") then","\t\t\tif stringFind(nStr, \"^0[-+]\") then","\t\t\t\tnStr = stringGsub(nStr, \"^0%+?\", \"\")","\t\t\telse","\t\t\t\t--","\t\t\t\t-- LuaJIT doesn't seem to be able to parse nStr if we output it as-is.","\t\t\t\t-- What is even the notation for complex numbers with a non-zero real part?","\t\t\t\t-- Oh LuaJIT, you're so mysterious...","\t\t\t\t--","\t\t\t\t-- @Robustness: Make sure we don't choke when trying to simplify() complex numbers.","\t\t\t\t--","\t\t\t\terrorf(2, \"Cannot output complex number '%s'.\", nStr)","\t\t\tend","\t\tend","","\t\treturn nStr","\tend","","\t-- Int (including 64-bit ints in Lua 5.3+, and excluding whole floats).","\tif n == mathFloor(n) and not (mathType and mathType(n) == \"float\") then","\t\tlocal nStr = F(\"%.0f\", n)","\t\tif tonumber(nStr) == n then  return nStr  end","\tend","","\t-- Anything else.","\treturn (tostring(n)","\t\t:gsub(\"(e[-+])0+(%d+)$\", \"%1%2\") -- Remove unnecessary zeroes after 'e'.","\t\t:gsub(\"e%+\",             \"e\"   ) -- Remove plus after 'e'.","\t)","end","","","","local tokenize","do","\tlocal ERROR_UNFINISHED_VALUE = {}","","\t-- success, equalSignCountIfLong|errorCode, ptr = parseStringlikeToken( s, ptr )","\tlocal function parseStringlikeToken(s, ptr)","\t\tlocal longEqualSigns       = stringMatch(s, \"^%[(=*)%[\", ptr)","\t\tlocal equalSignCountIfLong = longEqualSigns and #longEqualSigns","","\t\t-- Single line (comment).","\t\tif not equalSignCountIfLong then","\t\t\tlocal i1, i2 = stringFind(s, \"\\n\", ptr)","\t\t\tptr          = i2 and i2 + 1 or #s + 1","","\t\t-- Multiline.","\t\telse","\t\t\tptr = ptr + 1 + #longEqualSigns + 1","","\t\t\tlocal i1, i2 = stringFind(s, \"%]\"..longEqualSigns..\"%]\", ptr)","\t\t\tif not i1 then","\t\t\t\treturn false, ERROR_UNFINISHED_VALUE, 0","\t\t\tend","","\t\t\tptr = i2 + 1","\t\tend","","\t\treturn true, equalSignCountIfLong, ptr","\tend","","\tlocal function codepointToString(cp, buffer)","\t\tif cp \u003c 0 or cp \u003e 0x10ffff then","\t\t\t-- This error is actually incorrect as Lua supports codepoints up to 2^31.","\t\t\t-- This is probably an issue that no one will ever encounter!","\t\t\treturn false, F(\"Codepoint 0x%X (%.0f) is outside the valid range (0..10FFFF).\", cp, cp)","\t\tend","","\t\tif cp \u003c 128 then","\t\t\ttableInsert(buffer, stringChar(cp))","\t\t\treturn true","\t\tend","","\t\tlocal suffix = cp % 64","\t\tlocal c4     = 128 + suffix","\t\tcp           = (cp - suffix) / 64","","\t\tif cp \u003c 32 then","\t\t\ttableInsert(buffer, stringChar(192+cp))","\t\t\ttableInsert(buffer, stringChar(c4))","\t\t\treturn true","\t\tend","","\t\tsuffix   = cp % 64","\t\tlocal c3 = 128 + suffix","\t\tcp       = (cp - suffix) / 64","","\t\tif cp \u003c 16 then","\t\t\ttableInsert(buffer, stringChar(224+cp))","\t\t\ttableInsert(buffer, stringChar(c3))","\t\t\ttableInsert(buffer, stringChar(c4))","\t\t\treturn true","\t\tend","","\t\tsuffix = cp % 64","\t\tcp     = (cp - suffix) / 64","","\t\ttableInsert(buffer, stringChar(240+cp))","\t\ttableInsert(buffer, stringChar(128+suffix))","\t\ttableInsert(buffer, stringChar(c3))","\t\ttableInsert(buffer, stringChar(c4))","\t\treturn true","\tend","","\tlocal function parseStringContents(s, path, ptrStart, ptrEnd)","\t\tlocal ptr    = ptrStart","\t\tlocal buffer = {}","","\t\twhile ptr \u003c= ptrEnd do","\t\t\tlocal i1 = stringFind(s, \"\\\\\", ptr, true)","\t\t\tif not i1 or i1 \u003e ptrEnd then  break  end","","\t\t\tif i1 \u003e ptr then","\t\t\t\ttableInsert(buffer, stringSub(s, ptr, i1-1))","\t\t\tend","\t\t\tptr = i1 + 1","","\t\t\t-- local b1, b2, b3 = stringByte(s, ptr, ptr+2)","","\t\t\tif     stringFind(s, \"^a\", ptr) then  tableInsert(buffer, \"\\a\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^b\", ptr) then  tableInsert(buffer, \"\\b\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^t\", ptr) then  tableInsert(buffer, \"\\t\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^n\", ptr) then  tableInsert(buffer, \"\\n\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^v\", ptr) then  tableInsert(buffer, \"\\v\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^f\", ptr) then  tableInsert(buffer, \"\\f\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^r\", ptr) then  tableInsert(buffer, \"\\r\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^\\\\\",ptr) then  tableInsert(buffer, \"\\\\\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, '^\"', ptr) then  tableInsert(buffer, \"\\\"\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^'\", ptr) then  tableInsert(buffer, \"\\'\") ; ptr = ptr + 1","\t\t\telseif stringFind(s, \"^\\n\",ptr) then  tableInsert(buffer, \"\\n\") ; ptr = ptr + 1","","\t\t\telseif stringFind(s, \"^z\", ptr) then","\t\t\t\tlocal i1, i2 = stringFind(s, \"^%s*\", ptr+1)","\t\t\t\tptr          = i2 + 1","","\t\t\telseif stringFind(s, \"^%d\", ptr) then","\t\t\t\tlocal nStr = stringMatch(s, \"^%d%d?%d?\", ptr)","\t\t\t\tlocal byte = tonumber(nStr)","","\t\t\t\tif byte \u003e 255 then","\t\t\t\t\treturn nil, formatErrorInFile(","\t\t\t\t\t\ts, path, ptr, \"Tokenizer\",","\t\t\t\t\t\t\"Byte value '%s' is out-of-range in decimal escape sequence. (String starting %s)\",","\t\t\t\t\t\tnStr, getRelativeLocationText(getLineNumber(s, ptrStart), getLineNumber(s, ptr))","\t\t\t\t\t)","\t\t\t\tend","","\t\t\t\ttableInsert(buffer, stringChar(byte))","\t\t\t\tptr = ptr + #nStr","","\t\t\telseif stringFind(s, \"^x%x%x\", ptr) then","\t\t\t\tlocal hexStr = stringSub(s, ptr+1, ptr+2)","\t\t\t\tlocal byte   = tonumber(hexStr, 16)","","\t\t\t\ttableInsert(buffer, stringChar(byte))","\t\t\t\tptr = ptr + 3","","\t\t\telseif stringFind(s, \"^u{%x+}\", ptr) then","\t\t\t\tlocal hexStr = stringMatch(s, \"^%x+\", ptr+2)","\t\t\t\tlocal cp     = tonumber(hexStr, 16)","","\t\t\t\tlocal ok, err = codepointToString(cp, buffer)","\t\t\t\tif not ok then","\t\t\t\t\treturn nil, formatErrorInFile(","\t\t\t\t\t\ts, path, ptr+2, \"Tokenizer\",","\t\t\t\t\t\t\"%s (String starting %s)\",","\t\t\t\t\t\terr, getRelativeLocationText(getLineNumber(s, ptrStart), getLineNumber(s, ptr))","\t\t\t\t\t)","\t\t\t\tend","","\t\t\t\tptr = ptr + 3 + #hexStr","","\t\t\telse","\t\t\t\treturn nil, formatErrorInFile(","\t\t\t\t\ts, path, ptr-1, \"Tokenizer\",","\t\t\t\t\t\"Invalid escape sequence. (String starting %s)\",","\t\t\t\t\tgetRelativeLocationText(getLineNumber(s, ptrStart), getLineNumber(s, ptr))","\t\t\t\t)","\t\t\tend","","\t\tend","","\t\tif ptr \u003c= ptrEnd then","\t\t\ttableInsert(buffer, stringSub(s, ptr, ptrEnd))","\t\tend","","\t\treturn tableConcat(buffer)","\tend","","\t-- tokens, error = tokenize( luaString [, keepWhitespaceTokens=false ] [, pathForErrorMessages=\"?\" ] )","\t--[[local]] function tokenize(s, keepWhitespaceTokens, path)","\t\tassertArg1(\"tokenize\", 1, s, \"string\")","","\t\tif type(keepWhitespaceTokens) == \"string\" then","\t\t\tpath                 = keepWhitespaceTokens","\t\t\tkeepWhitespaceTokens = false","\t\telse","\t\t\tassertArg2(\"tokenize\", 2, keepWhitespaceTokens, \"boolean\",\"nil\")","\t\t\tassertArg2(\"tokenize\", 3, path,                 \"string\",\"nil\")","\t\tend","","\t\tif stringFind(s, \"\\r\", 1, true) then","\t\t\ts = stringGsub(s, \"\\r\\n?\", \"\\n\")","\t\tend","\t\tpath = path or \"?\"","","\t\tlocal tokens = {}","\t\tlocal count  = 0","\t\tlocal ptr    = 1","\t\tlocal ln     = 1","","\t\tlocal BYTES_NAME_START      = TOKEN_BYTES.NAME_START","\t\tlocal BYTES_DASH            = TOKEN_BYTES.DASH","\t\tlocal BYTES_NUM             = TOKEN_BYTES.NUM","\t\tlocal BYTES_QUOTE           = TOKEN_BYTES.QUOTE","\t\tlocal BYTES_SQUARE          = TOKEN_BYTES.SQUARE","\t\tlocal BYTES_DOT             = TOKEN_BYTES.DOT","\t\tlocal BYTES_PUNCT_TWO_CHARS = TOKEN_BYTES.PUNCT_TWO_CHARS","\t\tlocal BYTES_PUNCT_ONE_CHAR  = TOKEN_BYTES.PUNCT_ONE_CHAR","","\t\tlocal NUM_HEX_FRAC_EXP      = NUMERAL_PATTERNS.HEX_FRAC_EXP","\t\tlocal NUM_HEX_FRAC          = NUMERAL_PATTERNS.HEX_FRAC","\t\tlocal NUM_HEX_EXP           = NUMERAL_PATTERNS.HEX_EXP","\t\tlocal NUM_HEX               = NUMERAL_PATTERNS.HEX","\t\tlocal NUM_BIN               = NUMERAL_PATTERNS.BIN","\t\tlocal NUM_DEC_FRAC_EXP      = NUMERAL_PATTERNS.DEC_FRAC_EXP","\t\tlocal NUM_DEC_FRAC          = NUMERAL_PATTERNS.DEC_FRAC","\t\tlocal NUM_DEC_EXP           = NUMERAL_PATTERNS.DEC_EXP","\t\tlocal NUM_DEC               = NUMERAL_PATTERNS.DEC","","\t\twhile true do","\t\t\tlocal i1, i2 = stringFind(s, \"^[ \\t\\n]+\", ptr)","","\t\t\tif i1 then","\t\t\t\tif keepWhitespaceTokens then","\t\t\t\t\tlocal lnStart = ln","\t\t\t\t\tlocal tokRepr = stringSub(s, i1, i2)","\t\t\t\t\tln            = ln + countString(tokRepr, \"\\n\", true)","\t\t\t\t\tcount         = count + 1","","\t\t\t\t\ttokens[count] = {","\t\t\t\t\t\ttype           = \"whitespace\",","\t\t\t\t\t\tvalue          = tokRepr,","\t\t\t\t\t\trepresentation = tokRepr,","","\t\t\t\t\t\tsourceString   = s,","\t\t\t\t\t\tsourcePath     = path,","","\t\t\t\t\t\tlineStart      = lnStart,","\t\t\t\t\t\tlineEnd        = ln,","\t\t\t\t\t\tpositionStart  = i1,","\t\t\t\t\t\tpositionEnd    = i2,","\t\t\t\t\t}","","\t\t\t\telse","\t\t\t\t\tln = ln + countSubString(s, i1, i2, \"\\n\", true)","\t\t\t\tend","","\t\t\t\tptr = i2 + 1","\t\t\tend","","\t\t\tif ptr \u003e #s then  break  end","","\t\t\tlocal ptrStart = ptr","\t\t\tlocal lnStart  = ln","\t\t\tlocal b1, b2   = stringByte(s, ptr, ptr+1)","\t\t\tlocal tokType, tokRepr, tokValue","","\t\t\t-- Identifier/keyword.","\t\t\tif BYTES_NAME_START[b1] then","\t\t\t\tlocal i1, i2, word = stringFind(s, \"^(.[%w_]*)\", ptr)","\t\t\t\tptr      = i2+1","\t\t\t\ttokType  = KEYWORDS[word] and \"keyword\" or \"identifier\"","\t\t\t\ttokRepr  = stringSub(s, ptrStart, ptr-1)","\t\t\t\ttokValue = tokRepr","","\t\t\t-- Comment.","\t\t\telseif BYTES_DASH[b1] and BYTES_DASH[b2] then","\t\t\t\tptr = ptr + 2","","\t\t\t\tlocal ok, equalSignCountIfLong","\t\t\t\tok, equalSignCountIfLong, ptr = parseStringlikeToken(s, ptr)","","\t\t\t\tif not ok then","\t\t\t\t\tlocal errCode = equalSignCountIfLong","\t\t\t\t\tif errCode == ERROR_UNFINISHED_VALUE then","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Unfinished long comment.\")","\t\t\t\t\telse","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Invalid comment.\")","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\t-- Check for nesting of [[...]] which is deprecated in Lua. Sigh...","\t\t\t\tif equalSignCountIfLong and equalSignCountIfLong == 0 then","\t\t\t\t\tlocal pos = stringFind(s, \"[[\", ptrStart+4, true)","\t\t\t\t\tif pos and pos \u003c ptr then","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, pos, \"Tokenizer\", \"Cannot have nested comments. (Comment starting %s)\", getRelativeLocationText(lnStart, getLineNumber(s, pos)))","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\ttokType  = \"comment\"","\t\t\t\ttokRepr  = stringSub(s, ptrStart, ptr-1)","\t\t\t\ttokRepr  = equalSignCountIfLong and tokRepr or (stringFind(tokRepr, \"\\n$\") and tokRepr or tokRepr..\"\\n\") -- Make sure there's a newline at the end of single-line comments. (It may be missing if we've reached EOF.)","\t\t\t\ttokValue = equalSignCountIfLong and stringSub(tokRepr, 5+equalSignCountIfLong, -3-equalSignCountIfLong) or stringSub(tokRepr, 3, -2)","","\t\t\t-- Number.","\t\t\telseif BYTES_NUM[b1] or (BYTES_DOT[b1] and BYTES_NUM[b2]) then","\t\t\t\tlocal               pat, maybeInt, kind, i1, i2, numStr = NUM_HEX_FRAC_EXP, false, \"lua52hex\",  stringFind(s, NUM_HEX_FRAC_EXP, ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_HEX_FRAC,     false, \"lua52hex\",  stringFind(s, NUM_HEX_FRAC,     ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_HEX_EXP,      false, \"lua52hex\",  stringFind(s, NUM_HEX_EXP,      ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_HEX,          true,  \"\",          stringFind(s, NUM_HEX,          ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_BIN,          true,  \"binary\",    stringFind(s, NUM_BIN,          ptr) -- LuaJIT supports these, so why not.","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_DEC_FRAC_EXP, false, \"\",          stringFind(s, NUM_DEC_FRAC_EXP, ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_DEC_FRAC,     false, \"\",          stringFind(s, NUM_DEC_FRAC,     ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_DEC_EXP,      false, \"\",          stringFind(s, NUM_DEC_EXP,      ptr)","\t\t\t\tif not i1     then  pat, maybeInt, kind, i1, i2, numStr = NUM_DEC,          true,  \"\",          stringFind(s, NUM_DEC,          ptr)","\t\t\t\tif not numStr then  return nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Malformed number.\")","\t\t\t\tend end end end end end end end end","","\t\t\t\tlocal numStrFallback = numStr","","\t\t\t\tif jit then","\t\t\t\t\tif stringFind(s, \"^[Ii]\", i2+1) then -- Imaginary part of complex number.","\t\t\t\t\t\tnumStr = stringSub(s, i1, i2+1)","\t\t\t\t\t\ti2     = i2 + 1","","\t\t\t\t\telseif not maybeInt or stringFind(numStr, \".\", 1, true) then","\t\t\t\t\t\t-- void","\t\t\t\t\telseif stringFind(s, \"^[Uu][Ll][Ll]\", i2+1) then -- Unsigned 64-bit integer.","\t\t\t\t\t\tnumStr = stringSub(s, i1, i2+3)","\t\t\t\t\t\ti2     = i2 + 3","\t\t\t\t\telseif stringFind(s, \"^[Ll][Ll]\", i2+1) then -- Signed 64-bit integer.","\t\t\t\t\t\tnumStr = stringSub(s, i1, i2+2)","\t\t\t\t\t\ti2     = i2 + 2","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\tlocal n = tonumber(numStr)","","\t\t\t\tif not n and jit then","\t\t\t\t\tlocal chunk = loadstring(\"return \"..numStr)","\t\t\t\t\tn           = chunk and chunk() or n","\t\t\t\tend","","\t\t\t\tn = n or tonumber(numStrFallback)","","\t\t\t\tif not n then","\t\t\t\t\t-- Note: We know we're not running LuaJIT here as it supports hexadecimal floats and binary notation, thus we use numStrFallback instead of numStr.","","\t\t\t\t\t-- Support hexadecimal floats if we're running Lua 5.1.","\t\t\t\t\tif kind == \"lua52hex\" then","\t\t\t\t\t\tlocal                                _, intStr, fracStr, expStr","\t\t\t\t\t\tif     pat == NUM_HEX_FRAC_EXP then  _, intStr, fracStr, expStr = stringMatch(numStrFallback, NUM_HEX_FRAC_EXP)","\t\t\t\t\t\telseif pat == NUM_HEX_FRAC     then  _, intStr, fracStr         = stringMatch(numStrFallback, NUM_HEX_FRAC) ; expStr  = \"0\"","\t\t\t\t\t\telseif pat == NUM_HEX_EXP      then  _, intStr,          expStr = stringMatch(numStrFallback, NUM_HEX_EXP)  ; fracStr = \"\"","\t\t\t\t\t\telse return nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Internal error parsing the number '%s'.\", numStrFallback) end","","\t\t\t\t\t\tn = tonumber(intStr, 16) or 0 -- intStr may be \"\".","","\t\t\t\t\t\tlocal fracValue = 1","\t\t\t\t\t\tfor i = 1, #fracStr do","\t\t\t\t\t\t\tfracValue = fracValue / 16","\t\t\t\t\t\t\tn         = n + tonumber(stringSub(fracStr, i, i), 16) * fracValue","\t\t\t\t\t\tend","","\t\t\t\t\t\tn = n * 2 ^ stringGsub(expStr, \"^+\", \"\")","","\t\t\t\t\telseif kind == \"binary\" then","\t\t\t\t\t\tn = tonumber(stringSub(numStrFallback, 3), 2)","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\tif not n then","\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Invalid number.\")","\t\t\t\tend","","\t\t\t\tptr      = i2+1","\t\t\t\ttokType  = \"number\"","\t\t\t\ttokRepr  = numStr","\t\t\t\ttokValue = n","","\t\t\t\tif stringFind(s, \"^[%w_.]\", ptr) then","\t\t\t\t\tlocal after = stringMatch(s, \"^%.?%d+\", ptr) or stringMatch(s, \"^[%w_.][%w_.]?\", ptr)","\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Malformed number near '%s%s'.\", numStr, after)","\t\t\t\tend","","\t\t\t-- Quoted string.","\t\t\telseif BYTES_QUOTE[b1] then","\t\t\t\tlocal quote     = stringSub(s, ptr, ptr)","\t\t\t\tlocal quoteByte = stringByte(quote)","\t\t\t\tptr             = ptr + 1","","\t\t\t\tlocal pat = \"[\"..quote..\"\\\\\\n]\"","","\t\t\t\twhile true do","\t\t\t\t\tlocal i1 = stringFind(s, pat, ptr)","\t\t\t\t\tif not i1 then","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Unfinished string.\")","\t\t\t\t\tend","","\t\t\t\t\tptr          = i1","\t\t\t\t\tlocal b1, b2 = stringByte(s, ptr, ptr+1)","","\t\t\t\t\t-- '\"'","\t\t\t\t\tif b1 == quoteByte then","\t\t\t\t\t\tptr = ptr + 1","\t\t\t\t\t\tbreak","","\t\t\t\t\t-- '\\'","\t\t\t\t\telseif b1 == 92 then","\t\t\t\t\t\tptr = ptr + 1","","\t\t\t\t\t\tif b2 == 122 then -- 'z'","\t\t\t\t\t\t\tptr         = ptr + 1","\t\t\t\t\t\t\tlocal _, i2 = stringFind(s, \"^%s*\", ptr)","\t\t\t\t\t\t\tptr         = i2 + 1","\t\t\t\t\t\telse","\t\t\t\t\t\t\t-- Note: We don't have to look for multiple characters after the escape, like \\nnn - this algorithm works anyway.","\t\t\t\t\t\t\tif ptr \u003e #s then","\t\t\t\t\t\t\t\treturn nil, formatErrorInFile(","\t\t\t\t\t\t\t\t\ts, path, ptr, \"Tokenizer\",","\t\t\t\t\t\t\t\t\t\"Unfinished string after escape character. (String starting %s)\",","\t\t\t\t\t\t\t\t\tgetRelativeLocationText(lnStart, getLineNumber(s, ptr))","\t\t\t\t\t\t\t\t)","\t\t\t\t\t\t\tend","\t\t\t\t\t\t\tptr = ptr + 1 -- Just skip the next character, whatever it might be.","\t\t\t\t\t\tend","","\t\t\t\t\t-- '\\n'","\t\t\t\t\telseif b1 == 10 then","\t\t\t\t\t\t-- Lua, this is silly!","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptr, \"Tokenizer\", \"Unescaped newline in string (starting %s).\", getRelativeLocationText(lnStart, getLineNumber(s, ptr)))","","\t\t\t\t\telse","\t\t\t\t\t\tassert(false)","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\ttokType = \"string\"","\t\t\t\ttokRepr = stringSub(s, ptrStart, ptr-1)","","\t\t\t\tlocal chunk = loadstring(\"return \"..tokRepr, \"@\") -- Try to make Lua parse the string value before we fall back to our own parser which is probably slower.","\t\t\t\tif chunk then","\t\t\t\t\ttokValue = chunk()","\t\t\t\t\tassert(type(tokValue) == \"string\")","\t\t\t\telse","\t\t\t\t\tlocal stringValue, err = parseStringContents(s, path, ptrStart+1, ptr-2)","\t\t\t\t\tif not stringValue then  return nil, err  end","\t\t\t\t\ttokValue = stringValue","\t\t\t\tend","","\t\t\t-- Long string.","\t\t\telseif BYTES_SQUARE[b1] and stringFind(s, \"^=*%[\", ptr+1) then","\t\t\t\tlocal ok, equalSignCountIfLong","\t\t\t\tok, equalSignCountIfLong, ptr = parseStringlikeToken(s, ptr)","","\t\t\t\tif not ok then","\t\t\t\t\tlocal errCode = equalSignCountIfLong","\t\t\t\t\tif errCode == ERROR_UNFINISHED_VALUE then","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Unfinished long string.\")","\t\t\t\t\telse","\t\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Invalid long string.\")","\t\t\t\t\tend","\t\t\t\tend","","\t\t\t\ttokType = \"string\"","\t\t\t\ttokRepr = stringSub(s, ptrStart, ptr-1)","","\t\t\t\tlocal chunk, err = loadstring(\"return \"..tokRepr, \"@\")","\t\t\t\tif not chunk then","\t\t\t\t\terr = stringGsub(err, \"^:%d+: \", \"\")","\t\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Could not convert long string token to value. (%s)\", err)","\t\t\t\tend","\t\t\t\ttokValue = assert(chunk)()","\t\t\t\tassert(type(tokValue) == \"string\")","","\t\t\t-- Punctuation.","\t\t\telseif BYTES_DOT[b1] and stringFind(s, \"^%.%.\", ptr+1) then","\t\t\t\tptr      = ptr + 3","\t\t\t\ttokType  = \"punctuation\"","\t\t\t\ttokRepr  = stringSub(s, ptrStart, ptr-1)","\t\t\t\ttokValue = tokRepr","\t\t\telseif BYTES_PUNCT_TWO_CHARS[b1] and stringFind(s, \"^%.%.\", ptr) or stringFind(s, \"^[=~\u003c\u003e]=\", ptr) or stringFind(s, \"^::\", ptr) or stringFind(s, \"^//\", ptr) or stringFind(s, \"^\u003c\u003c\", ptr) or stringFind(s, \"^\u003e\u003e\", ptr) then","\t\t\t\tptr      = ptr + 2","\t\t\t\ttokType  = \"punctuation\"","\t\t\t\ttokRepr  = stringSub(s, ptrStart, ptr-1)","\t\t\t\ttokValue = tokRepr","\t\t\telseif BYTES_PUNCT_ONE_CHAR[b1] then","\t\t\t\tptr      = ptr + 1","\t\t\t\ttokType  = \"punctuation\"","\t\t\t\ttokRepr  = stringSub(s, ptrStart, ptr-1)","\t\t\t\ttokValue = tokRepr","","\t\t\telse","\t\t\t\treturn nil, formatErrorInFile(s, path, ptrStart, \"Tokenizer\", \"Unknown character.\")","\t\t\tend","\t\t\tassert(tokType)","","\t\t\tln    = ln + countString(tokRepr, \"\\n\", true)","\t\t\tcount = count + 1","","\t\t\ttokens[count] = {","\t\t\t\ttype           = tokType,","\t\t\t\tvalue          = tokValue,","\t\t\t\trepresentation = tokRepr,","","\t\t\t\tsourceString   = s,","\t\t\t\tsourcePath     = path,","","\t\t\t\tlineStart      = lnStart,","\t\t\t\tlineEnd        = ln,","\t\t\t\tpositionStart  = ptrStart,","\t\t\t\tpositionEnd    = ptr - 1,","\t\t\t}","","\t\t\t-- print(F(\"%4d %-11s '%s'\", count, tokType, (stringGsub(tokRepr, \"\\n\", \"\\\\n\"))))","\t\tend","","\t\treturn tokens","\tend","end","","-- tokens, error = tokenizeFile( path [, keepWhitespaceTokens=false ] )","local function tokenizeFile(path, keepWhitespaceTokens)","\tassertArg1(\"tokenizeFile\", 1, path,                 \"string\")","\tassertArg2(\"tokenizeFile\", 2, keepWhitespaceTokens, \"boolean\",\"nil\")","","\tlocal file, err = ioOpen(path, \"r\")","\tif not file then  return nil, F(\"Could not open file '%s'. (%s)\", ensurePrintable(path), ensurePrintable(err))  end","","\tlocal s = file:read(\"*a\")","\tfile:close()","","\treturn tokenize(s, (keepWhitespaceTokens or false), path)","end","","--","-- :TokenCreation","--","-- commentToken     = newToken( \"comment\",     contents )","-- identifierToken  = newToken( \"identifier\",  name )","-- keywordToken     = newToken( \"keyword\",     name )","-- numberToken      = newToken( \"number\",      number )","-- punctuationToken = newToken( \"punctuation\", punctuationString )","-- stringToken      = newToken( \"string\",      stringValue )","-- whitespaceToken  = newToken( \"whitespace\",  contents )","--","local function newToken(tokType, tokValue)","\tlocal tokRepr","","\tif tokType == \"keyword\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'keyword' token. (Got %s)\", type(tokValue))  end","\t\tif not KEYWORDS[tokValue]     then  errorf(2, \"Invalid keyword '%s'.\", tokValue)  end","\t\ttokRepr = tokValue","","\telseif tokType == \"identifier\" then","\t\tif type(tokValue) ~= \"string\"                then  errorf(2, \"Expected string value for 'identifier' token. (Got %s)\", type(tokValue))  end","\t\tif not stringFind(tokValue, \"^[%a_][%w_]*$\") then  errorf(2, \"Invalid identifier '%s'.\", tokValue)  end","\t\tif KEYWORDS[tokValue]                        then  errorf(2, \"Invalid identifier '%s'.\", tokValue)  end","\t\ttokRepr = tokValue","","\telseif tokType == \"number\" then","\t\tif type(tokValue) ~= \"number\" then","\t\t\terrorf(2, \"Expected number value for 'number' token. (Got %s)\", type(tokValue))","\t\tend","\t\ttokRepr = (","\t\t\ttokValue == 0 and NORMALIZE_MINUS_ZERO and \"0\"      or -- Avoid '-0' sometimes.","\t\t\ttokValue == 1/0                        and \"(1/0)\"  or","\t\t\ttokValue == -1/0                       and \"(-1/0)\" or","\t\t\ttokValue ~= tokValue                   and \"(0/0)\"  or","\t\t\tformatNumber(tokValue)","\t\t)","","\telseif tokType == \"string\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'string' token. (Got %s)\", type(tokValue))  end","\t\ttokRepr = stringGsub(F(\"%q\", tokValue), \"\\n\", \"n\")","","\telseif tokType == \"punctuation\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'punctuation' token. (Got %s)\", type(tokValue))  end","\t\tif not PUNCTUATION[tokValue]  then  errorf(2, \"Invalid punctuation '%s'.\", tokValue)  end","\t\ttokRepr = tokValue","","\telseif tokType == \"comment\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'comment' token. (Got %s)\", type(tokValue))  end","","\t\tif stringFind(tokValue, \"\\n\") then","\t\t\tlocal equalSigns = stringFind(tokValue, \"[[\", 1, true) and \"=\" or \"\"","","\t\t\twhile stringFind(tokValue, \"]\"..equalSigns..\"]\", 1, true) do","\t\t\t\tequalSigns = equalSigns..\"=\"","\t\t\tend","","\t\t\ttokRepr = F(\"--[%s[%s]%s]\", equalSigns, tokValue, equalSigns)","","\t\telse","\t\t\ttokRepr = F(\"--%s\\n\", tokValue)","\t\tend","","\telseif tokType == \"whitespace\" then","\t\tif type(tokValue) ~= \"string\"       then  errorf(2, \"Expected string value for 'whitespace' token. (Got %s)\", type(tokValue))  end","\t\tif tokValue == \"\"                   then  errorf(2, \"Value is empty.\")  end -- Having a token that is zero characters long would be weird, so we disallow it.","\t\tif stringFind(tokValue, \"[^ \\t\\n]\") then  errorf(2, \"Value has non-whitespace characters.\")  end","\t\ttokRepr = tokValue","","\telse","\t\terrorf(2, \"Invalid token type '%s'.\", tostring(tokType))","\tend","","\treturn {","\t\ttype           = tokType,","\t\tvalue          = tokValue,","\t\trepresentation = tokRepr,","","\t\tsourceString   = \"\",","\t\tsourcePath     = \"?\",","","\t\tlineStart      = 0,","\t\tlineEnd        = 0,","\t\tpositionStart  = 0,","\t\tpositionEnd    = 0,","\t}","end","","--","-- :TokenModification","--","-- updateToken( commentToken,     contents )","-- updateToken( identifierToken,  name )","-- updateToken( keywordToken,     name )","-- updateToken( numberToken,      number )","-- updateToken( punctuationToken, punctuationString )","-- updateToken( stringToken,      stringValue )","-- updateToken( whitespaceToken,  contents )","--","local function updateToken(tok, tokValue)","\t-- @Copypaste from newToken().","","\tif tok.type == \"keyword\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'keyword' token. (Got %s)\", type(tokValue))  end","\t\tif not KEYWORDS[tokValue]     then  errorf(2, \"Invalid keyword '%s'.\", tokValue)  end","\t\ttok.representation = tokValue","","\telseif tok.type == \"identifier\" then","\t\tif type(tokValue) ~= \"string\"                then  errorf(2, \"Expected string value for 'identifier' token. (Got %s)\", type(tokValue))  end","\t\tif not stringFind(tokValue, \"^[%a_][%w_]*$\") then  errorf(2, \"Invalid identifier '%s'.\", tokValue)  end","\t\tif KEYWORDS[tokValue]                        then  errorf(2, \"Invalid identifier '%s'.\", tokValue)  end","\t\ttok.representation = tokValue","","\telseif tok.type == \"number\" then","\t\tif type(tokValue) ~= \"number\" then","\t\t\terrorf(2, \"Expected number value for 'number' token. (Got %s)\", type(tokValue))","\t\tend","\t\ttok.representation = (","\t\t\ttokValue == 0 and NORMALIZE_MINUS_ZERO and \"0\"      or -- Avoid '-0' sometimes.","\t\t\ttokValue == 1/0                        and \"(1/0)\"  or","\t\t\ttokValue == -1/0                       and \"(-1/0)\" or","\t\t\ttokValue ~= tokValue                   and \"(0/0)\"  or","\t\t\tformatNumber(tokValue)","\t\t)","","\telseif tok.type == \"string\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'string' token. (Got %s)\", type(tokValue))  end","\t\ttok.representation = stringGsub(F(\"%q\", tokValue), \"\\n\", \"n\")","","\telseif tok.type == \"punctuation\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'punctuation' token. (Got %s)\", type(tokValue))  end","\t\tif not PUNCTUATION[tokValue]  then  errorf(2, \"Invalid punctuation '%s'.\", tokValue)  end","\t\ttok.representation = tokValue","","\telseif tok.type == \"comment\" then","\t\tif type(tokValue) ~= \"string\" then  errorf(2, \"Expected string value for 'comment' token. (Got %s)\", type(tokValue))  end","","\t\tif stringFind(tokValue, \"\\n\") then","\t\t\tlocal equalSigns = stringFind(tokValue, \"[[\", 1, true) and \"=\" or \"\"","","\t\t\twhile stringFind(tokValue, \"]\"..equalSigns..\"]\", 1, true) do","\t\t\t\tequalSigns = equalSigns..\"=\"","\t\t\tend","","\t\t\ttok.representation = F(\"--[%s[%s]%s]\", equalSigns, tokValue, equalSigns)","","\t\telse","\t\t\ttok.representation = F(\"--%s\\n\", tokValue)","\t\tend","","\telseif tok.type == \"whitespace\" then","\t\tif type(tokValue) ~= \"string\"       then  errorf(2, \"Expected string value for 'whitespace' token. (Got %s)\", type(tokValue))  end","\t\tif tokValue == \"\"                   then  errorf(2, \"Value is empty.\")  end -- Having a token that is zero characters long would be weird, so we disallow it.","\t\tif stringFind(tokValue, \"[^ \\t\\n]\") then  errorf(2, \"Value has non-whitespace characters.\")  end","\t\ttok.representation = tokValue","","\telse","\t\terrorf(2, \"Internal error: Invalid token type '%s'.\", tostring(tok.type))","\tend","","\ttok.value = tokValue","end","","local function cloneToken(tok)","\treturn {","\t\ttype           = tok.type,","\t\tvalue          = tok.value,","\t\trepresentation = tok.representation,","","\t\tsourceString   = tok.sourceString,","\t\tsourcePath     = tok.sourcePath,","","\t\tlineStart      = tok.lineStart,","\t\tlineEnd        = tok.lineEnd,","\t\tpositionStart  = tok.positionStart,","\t\tpositionEnd    = tok.positionEnd,","\t}","end","","local function concatTokens(tokens)","\tlocal parts = {}","","\tfor tok = 1, #tokens do","\t\tlocal tokRepr     =             tokens[tok  ].representation","\t\tlocal lastTokRepr = tok \u003e 1 and tokens[tok-1].representation","","\t\tif lastTokRepr and (","\t\t\t(stringFind(tokRepr, \"^[%w_]\") and stringFind(lastTokRepr, \"[%w_]$\")) or","\t\t\t(stringFind(tokRepr, \"^%.\"   ) and stringFind(lastTokRepr, \"%.$\"   )) or","\t\t\t(stringFind(tokRepr, \"^%-\"   ) and stringFind(lastTokRepr, \"%-$\"   )) or","\t\t\t(stringFind(tokRepr, \"^/\"    ) and stringFind(lastTokRepr, \"/$\"    )) or","","\t\t\t(tok \u003e 1 and tokens[tok-1].type == \"number\" and stringFind(tokRepr,     \"^[%w_.]\")) or","\t\t\t(            tokens[tok  ].type == \"number\" and stringFind(lastTokRepr, \"%.$\") and not stringFind(lastTokRepr, \"%.%.$\"))","\t\t) then","\t\t\ttableInsert(parts, \" \")","\t\tend","\t\ttableInsert(parts, tokRepr)","\tend","","\treturn tableConcat(parts)","end","","","","local function isToken(token, tokType, tokValue)","\treturn token ~= nil and token.type == tokType and token.value == tokValue","end","","local function isTokenType(token, tokType)","\treturn token ~= nil and token.type == tokType","end","","local function isTokenAnyValue(token, tokValueSet)","\treturn token ~= nil and tokValueSet[token.value] == true","end","","","","local function getLeftmostToken(node)","\tif node.type == \"binary\" then","\t\treturn getLeftmostToken(node.left)","\telse","\t\treturn node.token","\tend","end","","","","local parseExpressionInternal, parseExpressionList, parseFunctionParametersAndBody, parseBlock","","local function parseIdentifier(tokens, tok) --\u003e ident, token, error","\tif not isTokenType(tokens[tok], \"identifier\") then","\t\treturn nil, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected an identifier.\")","\tend","","\tlocal ident = AstIdentifier(tokens[tok], tokens[tok].value)","\ttok         = tok + 1","","\treturn ident, tok","end","","local function parseNameList(tokens, tok, names, allowVararg, allowAttributes) --\u003e success, token, error|nil","\twhile true do","\t\tif allowVararg and isToken(tokens[tok], \"punctuation\", \"...\") then","\t\t\tlocal vararg = AstVararg(tokens[tok])","\t\t\ttok          = tok + 1 -- '...'","","\t\t\ttableInsert(names, vararg)","","\t\t\treturn true, tok","\t\tend","","\t\tlocal ident, tokNext, err = parseIdentifier(tokens, tok)","\t\tif not ident then  return false, tok, err  end","\t\ttok = tokNext","","\t\tif allowAttributes and isToken(tokens[tok], \"punctuation\", \"\u003c\") then","\t\t\ttok = tok + 1 -- '\u003c'","","\t\t\tlocal attrIdent, tokNext, err = parseIdentifier(tokens, tok)","\t\t\tif not attrIdent then","\t\t\t\treturn false, tok, err","\t\t\telseif not (attrIdent.name == \"close\" or attrIdent.name == \"const\") then","\t\t\t\treturn false, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'close' or 'const' for attribute name.\")","\t\t\tend","\t\t\ttok = tokNext","","\t\t\tident.attribute = attrIdent.name","","\t\t\tif not isToken(tokens[tok], \"punctuation\", \"\u003e\") then","\t\t\t\treturn nil, tok, formatErrorAfterToken(tokens[tok-1], \"Parser\", \"Expected '\u003e' after attribute name.\")","\t\t\tend","\t\t\ttok = tok + 1 -- '\u003e'","\t\tend","","\t\ttableInsert(names, ident)","","\t\tif not isToken(tokens[tok], \"punctuation\", \",\") then","\t\t\treturn true, tok","\t\tend","\t\ttok = tok + 1 -- ','","\tend","","\treturn true, tok","end","","local function parseTable(tokens, tokStart) --\u003e tableNode, token, error","\tlocal tok       = tokStart","\tlocal tableNode = AstTable(tokens[tok])","\ttok             = tok + 1 -- '{'","","\tlocal generatedIndex = 0","","\twhile true do","\t\tif isToken(tokens[tok], \"punctuation\", \"}\") then","\t\t\ttok = tok + 1 -- '}'","\t\t\tbreak","","\t\telseif isToken(tokens[tok], \"punctuation\", \"[\") then","\t\t\ttok = tok + 1 -- '['","","\t\t\tlocal keyExpr, tokNext, err = parseExpressionInternal(tokens, tok, 0)","\t\t\tif not keyExpr then  return nil, tok, err  end","\t\t\ttok = tokNext","","\t\t\tif not isToken(token