 ';'","\t\t\t-- Continue...","","\t\telseif isToken(tokens[tok], \"punctuation\", \"}\") then","\t\t\ttok = tok + 1 -- '}'","\t\t\tbreak","","\t\telse","\t\t\treturn nil, tok, formatErrorAfterToken(","\t\t\t\ttokens[tok-1], \"Parser\",","\t\t\t\t\"Expected ',' or '}' after value in table constructor (starting %s).\",","\t\t\t\tgetRelativeLocationTextForToken(tokens, tokStart, tok-1)","\t\t\t)","\t\tend","\tend","","\treturn tableNode, tok","end","","--[[local]] function parseExpressionInternal(tokens, tokStart, lastPrecedence) --\u003e expression, token, error","\tlocal tok                  = tokStart","\tlocal canParseLookupOrCall = false","\tlocal currentToken         = tokens[tok]","\tlocal expr","","\t-- identifier","\tif isTokenType(currentToken, \"identifier\") then","\t\tlocal ident, tokNext, err = parseIdentifier(tokens, tok)","\t\tif not ident then  return nil, tok, err  end","\t\ttok = tokNext","","\t\texpr                 = ident","\t\tcanParseLookupOrCall = true","","\t-- ...","\telseif isToken(currentToken, \"punctuation\", \"...\") then","\t\tlocal vararg = AstVararg(currentToken)","\t\ttok          = tok + 1 -- '...'","\t\texpr         = vararg","","\t-- literal","\telseif isTokenType(currentToken, \"string\") or isTokenType(currentToken, \"number\") then","\t\tlocal literal = AstLiteral(currentToken, currentToken.value)","\t\ttok           = tok + 1 -- literal","\t\texpr          = literal","\telseif isToken(currentToken, \"keyword\", \"true\") then","\t\tlocal literal = AstLiteral(currentToken, true)","\t\ttok           = tok + 1 -- 'true'","\t\texpr          = literal","\telseif isToken(currentToken, \"keyword\", \"false\") then","\t\tlocal literal = AstLiteral(currentToken, false)","\t\ttok           = tok + 1 -- 'false'","\t\texpr          = literal","\telseif isToken(currentToken, \"keyword\", \"nil\") then","\t\tlocal literal = AstLiteral(currentToken, nil)","\t\ttok           = tok + 1 -- 'nil'","\t\texpr          = literal","","\t-- unary","\telseif","\t\t(isToken(currentToken, \"keyword\", \"not\") or (isTokenType(currentToken, \"punctuation\") and isTokenAnyValue(currentToken, OPERATORS_UNARY)))","\t\tand OPERATOR_PRECEDENCE.unary \u003e lastPrecedence","\tthen","\t\tlocal unary = AstUnary(currentToken, currentToken.value)","\t\ttok         = tok + 1 -- operator","","\t\tlocal subExpr, tokNext, err = parseExpressionInternal(tokens, tok, OPERATOR_PRECEDENCE.unary-1)","\t\tif not subExpr then  return nil, tok, err  end","\t\tunary.expression = subExpr","\t\ttok              = tokNext","","\t\texpr = unary","","\t\t-- Special rule: Treat '-n' as one literal (but not '-n^n' because of operator precedence).","\t\tif","\t\t\tunary.operator == \"-\"","\t\t\tand subExpr.type == \"literal\"","\t\t\tand type(subExpr.value) == \"number\"","\t\t\tand isTokenType(subExpr.token, \"number\")","\t\t\tand not (subExpr.value == 0 and NORMALIZE_MINUS_ZERO) -- We cannot store -0 in Lua 5.3+, thus we need to keep the unary expression.","\t\tthen","\t\t\tsubExpr.value = -subExpr.value","\t\t\tsubExpr.token = unary.token","\t\t\texpr          = subExpr","\t\tend","","\t-- {...}","\telseif isToken(currentToken, \"punctuation\", \"{\") then","\t\tlocal tableNode, tokNext, err = parseTable(tokens, tok)","\t\tif not tableNode then  return nil, tok, err  end","\t\ttok = tokNext","","\t\texpr = tableNode","","\t-- function","\telseif isToken(currentToken, \"keyword\", \"function\") then","\t\tlocal funcTok = tok","\t\ttok           = tok + 1 -- 'function'","","\t\tlocal func, tokNext, err = parseFunctionParametersAndBody(tokens, tok, funcTok)","\t\tif not func then  return nil, tok, err  end","\t\tfunc.token = tok","\t\ttok        = tokNext","","\t\texpr = func","","\t-- (...)","\telseif isToken(currentToken, \"punctuation\", \"(\") then","\t\ttok = tok + 1 -- '('","","\t\tlocal _expr, tokNext, err = parseExpressionInternal(tokens, tok, 0)","\t\tif not _expr then  return nil, tok, err  end","\t\ttok = tokNext","","\t\tif _expr.ty