tToken, \"punctuation\", \"{\") then","\t\t\tlocal call = AstCall(currentToken)","","\t\t\tlocal tableNode, tokNext, err = parseTable(tokens, tok)","\t\t\tif not tableNode then  return nil, tok, err  end","\t\t\tcall.arguments[1] = tableNode","\t\t\ttok               = tokNext","","\t\t\tcall.callee = expr","\t\t\texpr        = call","","\t\t-- f()","\t\telseif isToken(currentToken, \"punctuation\", \"(\") then","\t\t\tif tok \u003e= 2 and currentToken.lineStart \u003e tokens[tok-1].lineEnd then","\t\t\t\treturn nil, tok, formatErrorAtToken(currentToken, \"Parser\", \"Ambigous syntax. Is this a function call or a new statement?\")","\t\t\tend","","\t\t\tlocal call = AstCall(currentToken)","\t\t\ttok        = tok + 1 -- '('","","\t\t\tif not isToken(tokens[tok], \"punctuation\", \")\") then","\t\t\t\tlocal ok, tokNext, err = parseExpressionList(tokens, tok, call.arguments)","\t\t\t\tif not ok then  return nil, tok, err  end","\t\t\t\ttok = tokNext","\t\t\tend","","\t\t\tif not isToken(tokens[tok], \"punctuation\", \")\") then","\t\t\t\treturn nil, tok, formatErrorAfterToken(tokens[tok-1], \"Parser\", \"Expected ')' to end argument list for call.\")","\t\t\tend","\t\t\ttok = tok + 1 -- ')'","","\t\t\tcall.callee = expr","\t\t\texpr        = call","","\t\t-- o:m()","\t\telseif isToken(currentToken, \"punctuation\", \":\") then","\t\t\tdo","\t\t\t\tlocal lookup = AstLookup(currentToken)","\t\t\t\ttok          = tok + 1 -- ':'","","\t\t\t\tlocal ident, tokNext, err = parseIdentifier(tokens, tok)","\t\t\t\tif not ident then  return nil, tok, err  end","\t\t\t\ttok = tokNext","","\t\t\t\tlocal literal = AstLiteral(ident.token, ident.name)","","\t\t\t\tlookup.object = expr","\t\t\t\tlookup.member = literal","","\t\t\t\texpr = lookup","\t\t\tend","","\t\t\tdo","\t\t\t\tlocal call  = AstCall(tokens[tok])","\t\t\t\tcall.method = true","","\t\t\t\tif isTokenType(tokens[tok], \"string\") then","\t\t\t\t\tlocal literal     = AstLiteral(tokens[tok], tokens[tok].value)","\t\t\t\t\t