,"\tend","end","","--[[local]] function parseFunctionParametersAndBody(tokens, tokStart, funcTok) --\u003e func, token, error","\tlocal tok  = tokStart","\tlocal func = AstFunction(tokens[funcTok])","","\tif not isToken(tokens[tok], \"punctuation\", \"(\") then","\t\treturn nil, tok, formatErrorAfterToken(tokens[tok-1], \"Parser\", \"Expected '(' to start parameter list for function.\")","\tend","\ttok = tok + 1 -- '('","","\tif not isToken(tokens[tok], \"punctuation\", \")\") then","\t\tlocal ok, tokNext, err = parseNameList(tokens, tok, func.parameters, true, false)","\t\tif not ok then  return nil, tok, err  end","\t\ttok = tokNext","\t\t-- @Cleanup: Move the vararg parameter parsing here.","\tend","","\tif not isToken(tokens[tok], \"punctuation\", \")\") then","\t\treturn nil, tok, formatErrorAfterToken(tokens[tok-1], \"Parser\", \"Expected ')' to end parameter list for function.\")","\tend","\ttok = tok + 1 -- ')'","","\tlocal block, tokNext, err = parseBlock(tokens, tok, tok-1, true)","\tif not block then  return nil, tok, err  end","\tfunc.body = block","\ttok       = tokNext","","\tif not isToken(tokens[tok], \"keyword\", \"end\") then","\t\treturn nil, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'end' to end function (starting %s).\", getRelativeLocationTextForToken(tokens, tokStart, tok))","\tend","\ttok = tok + 1 -- 'end'","","\treturn func, tok","end","","local BLOCK_END_TOKEN_TYPES = newSet{ \"end\", \"else\", \"elseif\", \"until\" }","","local function parseOneOrPossiblyMoreStatements(tokens, tokStart, statements) --\u003e success, token, error  -- The error message may be empty.","\t--[[","\tstat ::= ';'","\t         varlist '=' explist |","\t         functioncall |","\t         label |","\t         break |","\t         goto Name |","\t         do block end |","\t         while exp do block end |","\t         repeat block until exp |","\t         if exp then block {elseif exp then block} [else block] end |","\t         for Name '=' exp ',' exp [',' exp] do block end |","\t         for namelist in explist do block end |","\t         function funcname funcbody |","\t         local function Name funcbody |","\t         local attnamelist ['=' explist]","","\tretstat ::= return [explist] [';']","\t]]","\tlocal tok          = tokStart","\tlocal currentToken = tokens[tok]","","\t-- do","\tif isToken(currentToken, \"keyword\", \"do\") then","\t\ttok = tok + 1 -- 'do'","","\t\tlocal block, tokNext, err = parseBlock(tokens, tok, tok-1, true)","\t\tif not block then  return false, tok, err  end","\t\tblock.token = tok - 1","\t\ttok         = tokNext","","\t\tif not isToken(tokens[tok], \"keyword\", \"end\") then","\t\t\treturn false, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'end' to end 'do' block (starting %s).\", getRelativeLocationTextForToken(tokens, tokStart, tok))","\t\tend","\t\ttok = tok + 1 -- 'end'","","\t\ttableInsert(statements, block)","\t\treturn true, tok","","\t-- while","\telseif isToken(currentToken, \"keyword\", \"while\") then","\t\tlocal whileLoop = AstWhile(currentToken)","\t\ttok             = tok + 1 -- 'while'","","\t\tlocal expr, tokNext, err = parseExpressionInternal(tokens, tok, 0)","\t\tif not expr then  return false, tok, err  end","\t\twhileLoop.condition = expr","\t\ttok                 = tokNext","","\t\tif not isToken(tokens[tok], \"keyword\", \"do\") then","\t\t\treturn false, tok, formatErrorAfterToken(tokens[tok-1], \"Parser\", \"Expected 'do' to start body for 'while' loop.\")","\t\tend","\t\ttok = tok + 1 -- 'do'","","\t\tlocal block, tokNext, err = parseBlock(tokens, tok, tok-1, true)","\t\tif not block then  return false, tok, err  end","\t\tblock.token    = tok - 1","\t\twhileLoop.body = block","\t\ttok            = tokNext","","\t\tif not isToken(tokens[tok], \"keyword\", \"end\") then","\t\t\treturn false, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'end' to end 'while' loop (starting %s).\", getRelativeLocationTextForToken(tokens, tokStart, tok))","\t\tend","\t\ttok = tok + 1 -- 'end'","","\t\ttableInsert(statements, whileLoop)","\t\treturn true, tok","","\t-- repeat","\telseif isToken(currentToken, \"keyword\", \"repeat\") then","\t\tlocal repeatLoop = AstRepeat(currentToken)","\t\ttok              = tok + 1 -- 'repeat'","","\t\tlocal block, tokNext, err = parseBlock(tokens, tok, tok-1, true)","\t\tif not block then  return false, tok, err  end","\t\trepeatLoop.body = block","\t\ttok             = tokNext","","\t\tif not isToken(tokens[tok], \"keyword\", \"until\") then","\t\t\treturn false, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'until' at the end of 'repeat' loop (starting %s).\", getRelativeLocationTextForToken(tokens, tokStart, tok))","\t\tend","\t\ttok = tok + 1 -- 'until'","","\t\tlocal expr, tokNext, err = parseExpressionInternal(tokens, tok, 0)","\t\tif not expr then  return false, tok, err  end","\t\trepeatLoop.condition = expr","\t\ttok                  = tokNext","","\t\ttableInsert(statements, repeatLoop)","\t\treturn true, tok","","\t-- if","\telseif isToken(currentToken, \"keyword\", \"if\") then","\t\tlocal ifNode = AstIf(currentToken)","\t\ttok          = tok + 1 -- 'if'","","\t\tlocal expr, tokNext, err = parseExpressionInternal(tokens, tok, 0)","\t\tif not expr then  return false, tok, err  end","\t\tifNode.condition = expr","\t\ttok              = tokNext","","\t\tif not isToken(tokens[tok], \"keyword\", \"then\") then","\t\t\treturn false, tok, formatErrorAtToken(tokens[tok], \"Parser\", \"Expected 'then' after 'if' condition.\")","\t\tend","\t\ttok = tok + 1 -- 'then'","","\t\tlocal block, tokNext, err = parseBlock(tokens, tok, tok-1, true)","\t\tif not block then  return false, tok, err  end","\t\tifNode.bodyTrue = block","\t\ttok             = tokNext","","\t\tlocal ifNodeLeaf = ifNode","","\t\twhile isToken(tokens[tok], \"keyword\", \"elseif\") do","\t\t\ttok = tok + 1 -- 'elseif'","","\t\t\tifNodeLeaf.bodyFalse               = AstBlock(tokens[